 1вҶ’import type { QueueItemRow, WeekTemplate, Session } from "../types";
 2вҶ’
 3вҶ’
 4вҶ’export interface UpcomingItem {
 5вҶ’  type: "session" | "spacer";
 6вҶ’  sessionId?: string;
 7вҶ’  title: string;
 8вҶ’  exerciseCount?: number;
 9вҶ’  color?: string;
10вҶ’}
11вҶ’
12вҶ’export function computeUpcoming(
13вҶ’  pendingItems: QueueItemRow[],
14вҶ’  template: WeekTemplate,
15вҶ’  sessions: Session[],
16вҶ’  maxSessions: number
17вҶ’): UpcomingItem[] {
18вҶ’  const sessionMap = new Map(sessions.map((s) => [s.id, s]));
19вҶ’
20вҶ’  // Build the template rhythm: which day indices are spacers vs sessions
21вҶ’  const templateRhythm: Array<{ type: "session" | "spacer"; sessionId?: string }> = [];
22вҶ’  for (const day of template.days) {
23вҶ’    const mainIds = (day.sessionIDs ?? []).filter((sid) => {
24вҶ’      const s = sessionMap.get(sid);
25вҶ’      return s && !s.isDaily;
26вҶ’    });
27вҶ’    if (mainIds.length === 0 && (day.sessionIDs ?? []).length > 0) {
28вҶ’      templateRhythm.push({ type: "spacer" });
29вҶ’    } else if (mainIds.length > 0) {
30вҶ’      for (const sid of mainIds) {
31вҶ’        templateRhythm.push({ type: "session", sessionId: sid });
32вҶ’      }
33вҶ’    }
34вҶ’  }
35вҶ’
36вҶ’  const result: UpcomingItem[] = [];
37вҶ’  let rhythmIndex = 0;
38вҶ’  let sessionCount = 0;
39вҶ’
40вҶ’  const firstPending = pendingItems[0];
41вҶ’  if (firstPending) {
42вҶ’    for (let i = 0; i < templateRhythm.length; i++) {
43вҶ’      if (templateRhythm[i].sessionId === firstPending.session_id) {
44вҶ’        rhythmIndex = i;
45вҶ’        break;
46вҶ’      }
47вҶ’    }
48вҶ’  }
49вҶ’
50вҶ’  let pendingIdx = 0;
51вҶ’  while (sessionCount < maxSessions && pendingIdx < pendingItems.length) {
52вҶ’    const rhythmSlot = templateRhythm[rhythmIndex % templateRhythm.length];
53вҶ’
54вҶ’    if (rhythmSlot.type === "spacer") {
55вҶ’      result.push({ type: "spacer", title: "CARs only" });
56вҶ’    } else {
57вҶ’      const item = pendingItems[pendingIdx];
58вҶ’      const session = sessionMap.get(item.session_id);
59вҶ’      result.push({
60вҶ’        type: "session",
61вҶ’        sessionId: item.session_id,
62вҶ’        title: session?.title ?? item.session_id,
63вҶ’        exerciseCount: session?.exercises.length,
