129вҶ’    }
130вҶ’  }
131вҶ’
132вҶ’  const matches: CompletionMatch[] = [];
133вҶ’  const usedItems = new Set<number>();
134вҶ’
135вҶ’  for (const workout of workouts) {
136вҶ’    const routineId = getRoutineId(workout);
137вҶ’    if (!routineId) continue;
138вҶ’
139вҶ’    const itemId = routineToItem.get(routineId);
140вҶ’    if (itemId !== undefined && !usedItems.has(itemId)) {
