149вҶ’// в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
150вҶ’// autoMatchExercises
151вҶ’// в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
152вҶ’
153вҶ’/**
154вҶ’ * Normalize an exercise name for fuzzy matching:
155вҶ’ * - Lowercase
156вҶ’ * - Strip non-alphanumeric characters (spaces, hyphens, punctuation)
157вҶ’ * - Strip a trailing 's' (basic singular/plural normalisation)
158вҶ’ */
159вҶ’function normalizeName(name: string): string {
160вҶ’  return name
161вҶ’    .toLowerCase()
162вҶ’    .replace(/[^a-z0-9]/g, "")
163вҶ’    .replace(/s$/, "");
164вҶ’}
165вҶ’
166вҶ’/**
167вҶ’ * Attempt to automatically match program exercise names to Hevy exercise
168вҶ’ * template IDs using normalized name comparison. Supports partial matching
169вҶ’ * (one normalized name contains the other).
170вҶ’ *
171вҶ’ * Returns a Map of program exercise name вҶ’ Hevy template ID for every name
172вҶ’ * that could be matched.
173вҶ’ */
174вҶ’export function autoMatchExercises(
175вҶ’  programNames: string[],
176вҶ’  hevyTemplates: HevyExerciseTemplate[]
177вҶ’): Map<string, string> {
178вҶ’  const result = new Map<string, string>();
179вҶ’
180вҶ’  // Pre-normalize template names
181вҶ’  const normalizedTemplates = hevyTemplates.map((t) => ({
182вҶ’    id: t.id,
183вҶ’    norm: normalizeName(t.title),
184вҶ’  }));
185вҶ’
186вҶ’  for (const programName of programNames) {
187вҶ’    const normProgram = normalizeName(programName);
188вҶ’
189вҶ’    // Prefer exact match first
190вҶ’    let matched = normalizedTemplates.find((t) => t.norm === normProgram);
191вҶ’
192вҶ’    // Fall back to partial match (one contains the other)
193вҶ’    if (!matched) {
194вҶ’      matched = normalizedTemplates.find(
195вҶ’        (t) => t.norm.includes(normProgram) || normProgram.includes(t.norm)
196вҶ’      );
197вҶ’    }
198вҶ’
199вҶ’    if (matched) {
200вҶ’      result.set(programName, matched.id);
201вҶ’    }
202вҶ’  }
203вҶ’
204вҶ’  return result;
205вҶ’}
206вҶ’

