import type { Session, ExerciseMappingRow, QueueItemRow } from "../types";
import type { HevyRoutineExercise, HevySet, HevyWorkout, HevyExerciseTemplate } from "../hevy/client";

// в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
// Sets string parser
// в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

/**
 * Parse a sets string like "3Г—8", "3Г—30 sec", "2Г—45 sec", "3Г—1 min"
 * into an array of HevySet objects.
 *
 * - Patterns containing "sec" or "min" produce duration_seconds sets.
 * - All other patterns produce reps sets.
 */
function parseSetsString(setsStr: string): HevySet[] {
  // Normalise the multiplication sign вҖ” programs may use Г— (U+00D7) or x
  const normalised = setsStr.replace(/Г—/g, "x");

  // Match "NxM sec", "NxM min", or "NxM"
  const match = normalised.match(/^(\d+)\s*x\s*(\d+(?:\.\d+)?)\s*(sec|min)?/i);
  if (!match) {
    // Fallback: return a single normal set with no values
    return [{ type: "normal", reps: null, repRange: { start: null, end: null } }];
  }

  const count = parseInt(match[1], 10);
  const value = parseFloat(match[2]);
  const unit = match[3]?.toLowerCase();

  const isDuration = unit === "sec" || unit === "min";
  const duration_seconds = isDuration
    ? unit === "min"
      ? Math.round(value * 60)
      : Math.round(value)
    : undefined;

  const sets: HevySet[] = [];
  for (let i = 0; i < count; i++) {
    if (isDuration) {
      sets.push({ type: "normal", reps: null, repRange: { start: null, end: null }, duration_seconds });
    } else {
      const reps = Math.round(value);
      sets.push({ type: "normal", reps, repRange: { start: reps, end: reps } });
    }
  }
  return sets;
}

// в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
// buildRoutinePayload
// в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

export interface RoutinePayload {
  title: string;
  exercises: HevyRoutineExercise[];
  /** Exercise names from the session that had no mapping */
  unmapped: string[];
}

/**
 * Build a Hevy routine payload from a program session + exercise mappings.
 * Exercises without a mapping are collected in `unmapped` and omitted from
 * the payload.
 */
export function buildRoutinePayload(
  session: Session,
  mappings: ExerciseMappingRow[]
): RoutinePayload {
  const mappingMap = new Map(
    mappings.map((m) => [m.program_exercise_name, m.hevy_exercise_id])
  );

  const exercises: HevyRoutineExercise[] = [];
  const unmapped: string[] = [];

  for (const exercise of session.exercises) {
    const hevyId = mappingMap.get(exercise.name);
    if (!hevyId) {
      unmapped.push(exercise.name);
      continue;
    }

    let sets: HevySet[];
    if (typeof exercise.sets === "string") {
      sets = parseSetsString(exercise.sets);
    } else if (typeof exercise.sets === "number") {
      // Only a count provided вҖ” default to 1 rep per set
      sets = Array.from({ length: exercise.sets }, () => ({ type: "normal" as const, reps: 1, repRange: { start: 1, end: 1 } }));
    } else {
      sets = [{ type: "normal", reps: null, repRange: { start: null, end: null } }];
    }

    exercises.push({
      exercise_template_id: hevyId,
      sets,
      notes: exercise.notes,
    });
  }

  return { title: session.title, exercises, unmapped };
}

// в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
// matchCompletions
// в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

export interface CompletionMatch {
  queueItemId: number;
  workoutId: string;
}

/**
 * Match Hevy workouts to queue items by comparing each workout's routine ID
 * (obtained via `getRoutineId`) to the `hevy_routine_id` stored on the queue
 * item.
 *
 * Each workout is matched to at most one queue item.
 */
export function matchCompletions(
  items: Pick<QueueItemRow, "id" | "hevy_routine_id">[],
  workouts: HevyWorkout[],
  getRoutineId: (workout: HevyWorkout) => string | null
): CompletionMatch[] {
  // Build a map: routine_id вҶ’ queue item id
  const routineToItem = new Map<string, number>();
  for (const item of items) {
    if (item.hevy_routine_id) {
      routineToItem.set(item.hevy_routine_id, item.id);
    }
  }

  const matches: CompletionMatch[] = [];
  const usedItems = new Set<number>();

  for (const workout of workouts) {
    const routineId = getRoutineId(workout);
    if (!routineId) continue;

    const itemId = routineToItem.get(routineId);
    if (itemId !== undefined && !usedItems.has(itemId)) {
      matches.push({ queueItemId: itemId, workoutId: workout.id });
      usedItems.add(itemId);
    }
  }

  return matches;
}

// в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
// autoMatchExercises
// в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

/**
 * Normalize an exercise name for fuzzy matching:
 * - Lowercase
 * - Strip non-alphanumeric characters (spaces, hyphens, punctuation)
 * - Strip a trailing 's' (basic singular/plural normalisation)
 */
function normalizeName(name: string): string {
  return name
    .toLowerCase()
    .replace(/[^a-z0-9]/g, "")
    .replace(/s$/, "");
}

/**
 * Attempt to automatically match program exercise names to Hevy exercise
 * template IDs using normalized name comparison. Supports partial matching
 * (one normalized name contains the other).
 *
 * Returns a Map of program exercise name вҶ’ Hevy template ID for every name
 * that could be matched.
 */
export function autoMatchExercises(
  programNames: string[],
  hevyTemplates: HevyExerciseTemplate[]
): Map<string, string> {
  const result = new Map<string, string>();

  // Pre-normalize template names
  const normalizedTemplates = hevyTemplates.map((t) => ({
    id: t.id,
    norm: normalizeName(t.title),
  }));

  for (const programName of programNames) {
    const normProgram = normalizeName(programName);

    // Prefer exact match first
    let matched = normalizedTemplates.find((t) => t.norm === normProgram);

    // Fall back to partial match (one contains the other)
    if (!matched) {
      matched = normalizedTemplates.find(
        (t) => t.norm.includes(normProgram) || normProgram.includes(t.norm)
      );
    }

    if (matched) {
      result.set(programName, matched.id);
    }
  }

  return result;
}

import type { UserRow, QueueItemRow, ExerciseMappingRow } from "../types";

export async function getUser(db: D1Database, userId: string): Promise<UserRow | null> {
  return db.prepare("SELECT * FROM users WHERE id = ?").bind(userId).first<UserRow>();
}

export async function upsertUser(
  db: D1Database,
  user: { id: string; active_program: string; template_id: string; start_date: string; hevy_api_key?: string }
): Promise<void> {
  await db
    .prepare(
      `INSERT INTO users (id, active_program, template_id, start_date, hevy_api_key)
       VALUES (?, ?, ?, ?, ?)
       ON CONFLICT(id) DO UPDATE SET
         active_program = excluded.active_program,
         template_id = excluded.template_id,
         start_date = excluded.start_date,
         hevy_api_key = COALESCE(excluded.hevy_api_key, users.hevy_api_key)`
    )
    .bind(user.id, user.active_program, user.template_id, user.start_date, user.hevy_api_key ?? null)
    .run();
}

export async function getQueueItems(db: D1Database, userId: string): Promise<QueueItemRow[]> {
  const result = await db
    .prepare("SELECT * FROM queue_items WHERE user_id = ? ORDER BY position")
    .bind(userId)
    .all<QueueItemRow>();
  return result.results;
}

export async function insertQueueItems(
  db: D1Database,
  userId: string,
  items: Array<{ session_id: string; position: number }>
): Promise<void> {
  const stmt = db.prepare(
    "INSERT INTO queue_items (user_id, session_id, position) VALUES (?, ?, ?)"
  );
  const batch = items.map((item) => stmt.bind(userId, item.session_id, item.position));
  await db.batch(batch);
}

export async function markQueueItemCompleted(
  db: D1Database,
  itemId: number,
  completedDate: string,
  hevyWorkoutId?: string
): Promise<void> {
  await db
    .prepare(
      "UPDATE queue_items SET status = 'completed', completed_date = ?, hevy_workout_id = ? WHERE id = ?"
    )
    .bind(completedDate, hevyWorkoutId ?? null, itemId)
    .run();
}

export async function markQueueItemCompletedForUser(
  db: D1Database,
  itemId: number,
  userId: string,
  completedDate: string,
  hevyWorkoutId?: string
): Promise<void> {
  await db
    .prepare(
      "UPDATE queue_items SET status = 'completed', completed_date = ?, hevy_workout_id = ? WHERE id = ? AND user_id = ?"
    )
    .bind(completedDate, hevyWorkoutId ?? null, itemId, userId)
    .run();
}

export async function updateQueueItemHevyRoutineId(
  db: D1Database,
  itemId: number,
  routineId: string
): Promise<void> {
  await db
    .prepare("UPDATE queue_items SET hevy_routine_id = ? WHERE id = ?")
    .bind(routineId, itemId)
    .run();
}

export async function getExerciseMappings(
  db: D1Database,
  userId: string
): Promise<ExerciseMappingRow[]> {
  const result = await db
    .prepare("SELECT * FROM exercise_mappings WHERE user_id = ?")
    .bind(userId)
    .all<ExerciseMappingRow>();
  return result.results;
}

export async function upsertExerciseMapping(
  db: D1Database,
  mapping: ExerciseMappingRow
): Promise<void> {
  await db
    .prepare(
      `INSERT INTO exercise_mappings (user_id, program_exercise_name, hevy_exercise_id, confirmed_by_user)
       VALUES (?, ?, ?, ?)
       ON CONFLICT(user_id, program_exercise_name) DO UPDATE SET
         hevy_exercise_id = excluded.hevy_exercise_id,
         confirmed_by_user = excluded.confirmed_by_user`
    )
    .bind(mapping.user_id, mapping.program_exercise_name, mapping.hevy_exercise_id, mapping.confirmed_by_user)
    .run();
}

