142вҶ’            activeTab: "progress",
143вҶ’            ssePath: "/progress",
144вҶ’          })
145вҶ’        );
146вҶ’      }
147вҶ’
148вҶ’      // в”Җв”Җ GET /session/:id в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
149вҶ’      const sessionMatch = path.match(/^\/session\/([^/]+)$/);
150вҶ’      if (method === "GET" && sessionMatch) {
151вҶ’        const sessionId = decodeURIComponent(sessionMatch[1]);
152вҶ’
153вҶ’        if (isSSERequest(request)) {
154вҶ’          return await handleSessionSSE(env, auth.userId, sessionId);
155вҶ’        }
156вҶ’
157вҶ’        return htmlResponse(
158вҶ’          htmlShell({
159вҶ’            title: "Session",
160вҶ’            activeTab: "today",
161вҶ’            ssePath: `/session/${encodeURIComponent(sessionId)}`,
162вҶ’          })
163вҶ’        );
164вҶ’      }
165вҶ’
166вҶ’      // в”Җв”Җ POST /api/setup/:templateId в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
167вҶ’      const setupMatch = path.match(/^\/api\/setup\/([^/]+)$/);
168вҶ’      if (method === "POST" && (path === "/api/setup" || setupMatch)) {
169вҶ’        const urlTemplateId = setupMatch ? decodeURIComponent(setupMatch[1]) : undefined;
170вҶ’        return await handleSetup(request, env, auth.userId, urlTemplateId);
171вҶ’      }
172вҶ’
173вҶ’      // в”Җв”Җ POST /api/push-hevy/:id в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
174вҶ’      const pushMatch = path.match(/^\/api\/push-hevy\/([^/]+)$/);
175вҶ’      if (method === "POST" && pushMatch) {
176вҶ’        const sessionId = decodeURIComponent(pushMatch[1]);
177вҶ’        return await handlePush(env, auth.userId, sessionId);
178вҶ’      }
179вҶ’
180вҶ’      // в”Җв”Җ POST /api/pull в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
181вҶ’      if (method === "POST" && path === "/api/pull") {
182вҶ’        return await handlePull(env, auth.userId);
183вҶ’      }
184вҶ’
185вҶ’      // в”Җв”Җ POST /api/complete/:id в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
186вҶ’      const completeMatch = path.match(/^\/api\/complete\/([^/]+)$/);
187вҶ’      if (method === "POST" && completeMatch) {
188вҶ’        const itemId = parseInt(completeMatch[1], 10);
189вҶ’        return await handleManualComplete(env, auth.userId, itemId);
190вҶ’      }
191вҶ’
192вҶ’      // в”Җв”Җ 404 в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
193вҶ’      return new Response("Not Found", { status: 404 });
194вҶ’    } catch (err) {
195вҶ’      if (err instanceof Response) return err;
196вҶ’      const message = err instanceof Error ? err.message : "Internal Server Error";
197вҶ’      return new Response(message, { status: 500 });
198вҶ’    }
199вҶ’  },
200вҶ’};
201вҶ’
202вҶ’// в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
203вҶ’// Route handlers
204вҶ’// в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
205вҶ’
206вҶ’/** SSE: Today page вҖ” CARs card, hero session, completed, upcoming */
207вҶ’async function handleTodaySSE(env: Env, userId: string): Promise<Response> {
208вҶ’  const user = await getUser(env.DB, userId);
209вҶ’  if (!user) {
210вҶ’    return sseResponse(
211вҶ’      patchElements(setupPage(program.weekTemplates), { selector: "#content", mode: "inner" })
212вҶ’    );
213вҶ’  }
214вҶ’
215вҶ’  const items = await getQueueItems(env.DB, userId);
216вҶ’  const today = todayString();
217вҶ’  const sessionMap = new Map(program.sessions.map((s) => [s.id, s]));
218вҶ’
219вҶ’  const fragments: string[] = [];
220вҶ’
221вҶ’  // CARs card (daily session)
222вҶ’  const dailySession = program.sessions.find((s) => s.isDaily);
223вҶ’  if (dailySession) {
224вҶ’    fragments.push(patchElements(carsCard(dailySession), { selector: "#content", mode: "inner" }));
225вҶ’  }
226вҶ’
227вҶ’  // Hero session card вҖ” next pending
228вҶ’  const nextItem = getNextSession(items);
229вҶ’  if (nextItem) {
230вҶ’    const session = sessionMap.get(nextItem.session_id);
231вҶ’    if (session) {
232вҶ’      fragments.push(
233вҶ’        patchElements(heroSessionCard(session, nextItem), { selector: "#content", mode: "append" })
234вҶ’      );
235вҶ’    }
236вҶ’  }
237вҶ’
238вҶ’  // Completed today
239вҶ’  const completed = getCompletedSessions(items, today);
240вҶ’  if (completed.length > 0) {
241вҶ’    const completedData = completed.map((item) => ({
242вҶ’      title: sessionMap.get(item.session_id)?.title ?? item.session_id,
243вҶ’    }));
244вҶ’    fragments.push(
245вҶ’      patchElements(completedSection(completedData), { selector: "#content", mode: "append" })
246вҶ’    );
247вҶ’  }
248вҶ’
249вҶ’  // Upcoming (next 5 sessions)
250вҶ’  const template = program.weekTemplates.find((t) => t.id === user.template_id);
251вҶ’  if (template) {
252вҶ’    const pendingItems = items.filter((i) => i.status === "pending").sort((a, b) => a.position - b.position);
253вҶ’    // Skip the first pending (already shown as hero) for upcoming
254вҶ’    const upcomingPending = pendingItems.slice(1);
255вҶ’    const upcoming = computeUpcoming(upcomingPending, template, program.sessions, 5);
256вҶ’    if (upcoming.length > 0) {
257вҶ’      fragments.push(
258вҶ’        patchElements(upcomingSection(upcoming), { selector: "#content", mode: "append" })
259вҶ’      );
260вҶ’    }
261вҶ’  }
262вҶ’
263вҶ’  return sseResponse(mergeFragments(fragments));
264вҶ’}
265вҶ’
266вҶ’/** SSE: Progress page вҖ” skills, roadmap, benchmarks */
267вҶ’function handleProgressSSE(): Response {
268вҶ’  const fragments: string[] = [];
269вҶ’  let isFirst = true;
270вҶ’
271вҶ’  const addFragment = (html: string) => {
272вҶ’    fragments.push(patchElements(html, { selector: "#content", mode: isFirst ? "inner" : "append" }));
273вҶ’    isFirst = false;
274вҶ’  };
275вҶ’
276вҶ’  if (program.skills && program.skills.length > 0) {
277вҶ’    addFragment(skillCards(program.skills));
278вҶ’  }
279вҶ’
280вҶ’  if (program.roadmap && program.roadmap.length > 0) {
281вҶ’    addFragment(roadmapSection(program.roadmap));
282вҶ’  }
283вҶ’
284вҶ’  if (program.benchmarks && program.benchmarks.length > 0) {
285вҶ’    addFragment(benchmarksSection(program.benchmarks));
286вҶ’  }
287вҶ’
288вҶ’  return sseResponse(mergeFragments(fragments));
289вҶ’}
290вҶ’
291вҶ’/** SSE: Session detail вҖ” exercise list with coaching context */
292вҶ’async function handleSessionSSE(env: Env, userId: string, sessionId: string): Promise<Response> {
293вҶ’  const session = program.sessions.find((s) => s.id === sessionId);
294вҶ’  if (!session) {
295вҶ’    return sseResponse(
296вҶ’      patchElements(`<p>Session not found.</p>`, { selector: "#content", mode: "inner" })
297вҶ’    );
298вҶ’  }
299вҶ’
300вҶ’  // Look up user to determine current progression from start_date
301вҶ’  const user = await getUser(env.DB, userId);
302вҶ’  const currentProgression = user
303вҶ’    ? getCurrentProgression(user.start_date, program.progressions)
304вҶ’    : program.progressions[0];
305вҶ’
306вҶ’  const html = sessionDetailPage(session, currentProgression);
307вҶ’  return sseResponse(
308вҶ’    patchElements(html, { selector: "#content", mode: "inner" })
309вҶ’  );
310вҶ’}
