312вҶ’/** POST /api/setup вҖ” create user, generate queue, navigate to today */
313вҶ’async function handleSetup(request: Request, env: Env, userId: string, urlTemplateId?: string): Promise<Response> {
314вҶ’  let body: { apiKey?: string; startDate?: string; templateId?: string } = {};
315вҶ’  try {
316вҶ’    body = await request.json() as typeof body;
317вҶ’  } catch {
318вҶ’    // Body may be empty вҖ” that's OK, template ID comes from URL
319вҶ’  }
320вҶ’
321вҶ’  const templateId = urlTemplateId ?? body.templateId;
322вҶ’  const startDate = body.startDate || todayString();
323вҶ’  const apiKey = body.apiKey || undefined;
324вҶ’
325вҶ’  if (!templateId) {
326вҶ’    return new Response("Template ID is required", { status: 400 });
327вҶ’  }
328вҶ’
329вҶ’  const template = program.weekTemplates.find((t) => t.id === templateId);
330вҶ’  if (!template) {
331вҶ’    return new Response("Invalid template ID", { status: 400 });
332вҶ’  }
333вҶ’
334вҶ’  // Validate API key against Hevy before proceeding
335вҶ’  if (apiKey) {
336вҶ’    try {
337вҶ’      const client = new HevyClient(apiKey);
338вҶ’      await client.getExerciseTemplates(1, 1);
339вҶ’    } catch {
340вҶ’      return sseResponse(
341вҶ’        patchElements(
342вҶ’          `<div class="card"><p style="color:var(--orange)">Invalid Hevy API key. Check your key in Hevy Settings &gt; Developer and try again.</p></div>`,
343вҶ’          { selector: "#content", mode: "prepend" }
344вҶ’        )
345вҶ’      );
346вҶ’    }
347вҶ’  }
348вҶ’
349вҶ’  // Upsert user
350вҶ’  await upsertUser(env.DB, {
351вҶ’    id: userId,
352вҶ’    active_program: program.meta.title,
353вҶ’    template_id: templateId,
354вҶ’    start_date: startDate,
355вҶ’    hevy_api_key: apiKey,
356вҶ’  });
357вҶ’
358вҶ’  // Generate queue playlist
359вҶ’  const weeks = program.meta.durationWeeks || 8;
360вҶ’  const playlist = generatePlaylist(template, program.sessions, weeks);
361вҶ’  if (playlist.length > 0) {
362вҶ’    await insertQueueItems(env.DB, userId, playlist);
363вҶ’  }
364вҶ’
365вҶ’  // Redirect to Today page via script injection (Datastar v1 pattern)
366вҶ’  return sseResponse(executeScript("window.location.href = '/'"));
367вҶ’}
368вҶ’
369вҶ’/** POST /api/push-hevy/:id вҖ” push session to Hevy as routine */
370вҶ’async function handlePush(env: Env, userId: string, sessionId: string): Promise<Response> {
371вҶ’  const user = await getUser(env.DB, userId);
372вҶ’  if (!user || !user.hevy_api_key) {
373вҶ’    return sseResponse(
374вҶ’      patchElements(`<div class="card"><p>Connect your Hevy API key first.</p></div>`, {
375вҶ’        selector: "#content",
376вҶ’        mode: "inner",
377вҶ’      })
378вҶ’    );
379вҶ’  }
380вҶ’
381вҶ’  const session = program.sessions.find((s) => s.id === sessionId);
382вҶ’  if (!session) {
383вҶ’    return new Response("Session not found", { status: 404 });
384вҶ’  }
385вҶ’
386вҶ’  const client = new HevyClient(user.hevy_api_key);
387вҶ’
388вҶ’  // Get or auto-create exercise mappings
389вҶ’  let mappings = await getExerciseMappings(env.DB, userId);
390вҶ’  if (mappings.length === 0) {
391вҶ’    // First push: auto-match exercises
392вҶ’    try {
393вҶ’      const templates = await client.getAllExerciseTemplates();
394вҶ’      const programNames = program.sessions.flatMap((s) =>
395вҶ’        s.exercises.map((e) => e.name)
396вҶ’      );
397вҶ’      const autoMatched = autoMatchExercises(programNames, templates);
398вҶ’
399вҶ’      for (const [name, hevyId] of autoMatched) {
400вҶ’        await upsertExerciseMapping(env.DB, {
401вҶ’          user_id: userId,
402вҶ’          program_exercise_name: name,
403вҶ’          hevy_exercise_id: hevyId,
404вҶ’          confirmed_by_user: 0,
405вҶ’        });
406вҶ’      }
407вҶ’      mappings = await getExerciseMappings(env.DB, userId);
408вҶ’    } catch {
409вҶ’      // If auto-match fails, continue with empty mappings
410вҶ’    }
411вҶ’  }
412вҶ’
413вҶ’  const payload = buildRoutinePayload(session, mappings);
414вҶ’
415вҶ’  try {
416вҶ’    // Find existing queue item to update
417вҶ’    const items = await getQueueItems(env.DB, userId);
418вҶ’    const queueItem = items.find(
419вҶ’      (i) => i.session_id === sessionId && i.status === "pending"
420вҶ’    );
421вҶ’
422вҶ’    let routineId: string;
423вҶ’    if (queueItem?.hevy_routine_id) {
424вҶ’      // Update existing routine
425вҶ’      const routine = await client.updateRoutine(queueItem.hevy_routine_id, {
426вҶ’        title: payload.title,
427вҶ’        exercises: payload.exercises,
428вҶ’      });
429вҶ’      routineId = routine.id;
430вҶ’    } else {
431вҶ’      // Create new routine
432вҶ’      const routine = await client.createRoutine({
433вҶ’        title: payload.title,
434вҶ’        exercises: payload.exercises,
435вҶ’      });
436вҶ’      routineId = routine.id;
437вҶ’    }
438вҶ’
439вҶ’    // Store routine ID on queue item
440вҶ’    if (queueItem) {
441вҶ’      await updateQueueItemHevyRoutineId(env.DB, queueItem.id, routineId);
442вҶ’    }
443вҶ’
444вҶ’    const unmappedNote =
445вҶ’      payload.unmapped.length > 0
446вҶ’        ? `<p style="color:var(--orange);font-size:13px;margin-top:8px">${payload.unmapped.length} exercise(s) could not be mapped.</p>`
447вҶ’        : "";
448вҶ’
449вҶ’    return sseResponse(
450вҶ’      patchElements(
451вҶ’        `<div class="card"><p style="color:var(--green)">Pushed to Hevy!</p>${unmappedNote}</div>`,
452вҶ’        { selector: "#content", mode: "prepend" }
453вҶ’      )
454вҶ’    );
455вҶ’  } catch (err) {
456вҶ’    const msg = escapeHtml(err instanceof Error ? err.message : "Push failed");
457вҶ’    return sseResponse(
458вҶ’      patchElements(
459вҶ’        `<div class="card"><p style="color:var(--orange)">${msg}</p></div>`,
460вҶ’        { selector: "#content", mode: "prepend" }
461вҶ’      )
462вҶ’    );
463вҶ’  }
464вҶ’}
465вҶ’
466вҶ’/** POST /api/pull вҖ” pull completions from Hevy */
467вҶ’async function handlePull(env: Env, userId: string): Promise<Response> {
468вҶ’  const user = await getUser(env.DB, userId);
469вҶ’  if (!user || !user.hevy_api_key) {
470вҶ’    return sseResponse(
471вҶ’      patchElements(`<div class="card"><p>Connect your Hevy API key first.</p></div>`, {
472вҶ’        selector: "#content",
473вҶ’        mode: "inner",
474вҶ’      })
475вҶ’    );
476вҶ’  }
477вҶ’
478вҶ’  const client = new HevyClient(user.hevy_api_key);
479вҶ’
480вҶ’  try {
481вҶ’    const workouts = await client.getRecentWorkouts();
482вҶ’    const items = await getQueueItems(env.DB, userId);
483вҶ’    const pendingItems = items.filter((i) => i.status === "pending" && i.hevy_routine_id);
484вҶ’
485вҶ’    // Build a nameвҶ’routine_id lookup from pending items
486вҶ’    const nameToRoutineId = new Map<string, string>();
487вҶ’    for (const item of pendingItems) {
488вҶ’      const session = program.sessions.find((s) => s.id === item.session_id);
489вҶ’      if (session && item.hevy_routine_id) {
490вҶ’        nameToRoutineId.set(session.title, item.hevy_routine_id);
491вҶ’      }
492вҶ’    }
493вҶ’
494вҶ’    const matches = matchCompletions(
495вҶ’      pendingItems,
496вҶ’      workouts,
497вҶ’      (w) => nameToRoutineId.get(w.name) ?? null
498вҶ’    );
499вҶ’
500вҶ’    const today = todayString();
501вҶ’    for (const match of matches) {
502вҶ’      await markQueueItemCompleted(env.DB, match.queueItemId, today, match.workoutId);
503вҶ’    }
504вҶ’
505вҶ’    // Re-render today page
506вҶ’    return await handleTodaySSE(env, userId);
507вҶ’  } catch (err) {
508вҶ’    const msg = escapeHtml(err instanceof Error ? err.message : "Pull failed");
509вҶ’    return sseResponse(
510вҶ’      patchElements(
511вҶ’        `<div class="card"><p style="color:var(--orange)">${msg}</p></div>`,
512вҶ’        { selector: "#content", mode: "prepend" }
513вҶ’      )
514вҶ’    );
515вҶ’  }
516вҶ’}
517вҶ’
518вҶ’/** POST /api/complete/:id вҖ” manual complete, re-render today */
519вҶ’async function handleManualComplete(
520вҶ’  env: Env,
521вҶ’  userId: string,
522вҶ’  itemId: number
523вҶ’): Promise<Response> {
524вҶ’  if (!Number.isInteger(itemId)) {
525вҶ’    return new Response("Invalid item ID", { status: 400 });
526вҶ’  }
527вҶ’  const today = todayString();
528вҶ’  await markQueueItemCompletedForUser(env.DB, itemId, userId, today);
529вҶ’  return await handleTodaySSE(env, userId);
530вҶ’}
