#!/usr/bin/env node
// One-shot script to transform programs/mobility-joint-restoration.json
// from sessions-with-inline-exercises to exerciseTemplates + routines model.

import { readFileSync, writeFileSync } from "fs";
import { resolve, dirname } from "path";
import { fileURLToPath } from "url";

const __dirname = dirname(fileURLToPath(import.meta.url));
const inputPath = resolve(__dirname, "../programs/mobility-joint-restoration.json");
const program = JSON.parse(readFileSync(inputPath, "utf-8"));

// в”Җв”Җ Step 1: Identify exercise type/equipment/muscle group в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
// Map exercise IDs to Hevy-compatible metadata
const exerciseMeta = {
  // Daily CARs
  "neck-cars":                 { type: "reps_only", equip: "none", muscle: "neck", secondary: [] },
  "shoulder-cars":             { type: "reps_only", equip: "none", muscle: "shoulders", secondary: [] },
  "hip-cars":                  { type: "reps_only", equip: "none", muscle: "glutes", secondary: ["hip_flexors"] },
  "ankle-cars":                { type: "reps_only", equip: "none", muscle: "calves", secondary: [] },
  "spine-cars":                { type: "reps_only", equip: "none", muscle: "lower_back", secondary: ["abdominals"] },
  "wrist-cars":                { type: "reps_only", equip: "none", muscle: "forearms", secondary: [] },
  "tspine-rotation-quadruped": { type: "reps_only", equip: "none", muscle: "upper_back", secondary: ["shoulders"] },

  // Shoulder Rehab
  "dead-hangs":                { type: "duration", equip: "pull_up_bar", muscle: "lats", secondary: ["forearms", "shoulders"] },
  "tspine-extension-foam-roller": { type: "reps_only", equip: "foam_roller", muscle: "upper_back", secondary: [] },
  "open-book":                 { type: "reps_only", equip: "none", muscle: "upper_back", secondary: ["shoulders"] },
  "scapular-pushups":          { type: "bodyweight_reps", equip: "none", muscle: "chest", secondary: ["shoulders"] },
  "banded-external-rotation":  { type: "reps_only", equip: "resistance_band", muscle: "shoulders", secondary: [] },
  "prone-ytw-raises":          { type: "reps_only", equip: "dumbbell", muscle: "shoulders", secondary: ["upper_back"] },
  "wall-slides":               { type: "reps_only", equip: "none", muscle: "shoulders", secondary: ["upper_back"] },
  "shoulder-sleeper-stretch":  { type: "duration", equip: "none", muscle: "shoulders", secondary: [] },

  // Shared: Hollow Body Hold (in shoulder-rehab as -a, core-stability as -d)
  "hollow-body-hold":          { type: "duration", equip: "none", muscle: "abdominals", secondary: ["hip_flexors"] },

  // Knee & Hip
  "ninety-ninety-hip-switches": { type: "reps_only", equip: "none", muscle: "glutes", secondary: ["hip_flexors"] },
  "glute-bridge":              { type: "reps_only", equip: "none", muscle: "glutes", secondary: ["hamstrings"] },
  "banded-clamshells":         { type: "reps_only", equip: "resistance_band", muscle: "glutes", secondary: [] },
  "tibialis-raises":           { type: "bodyweight_reps", equip: "none", muscle: "calves", secondary: [] },
  "banded-tke":                { type: "reps_only", equip: "resistance_band", muscle: "quadriceps", secondary: [] },
  "atg-split-squat":           { type: "bodyweight_reps", equip: "none", muscle: "quadriceps", secondary: ["glutes", "calves"] },
  "cossack-squat":             { type: "bodyweight_reps", equip: "none", muscle: "quadriceps", secondary: ["glutes", "hamstrings"] },
  "active-frog-stretch":       { type: "duration", equip: "none", muscle: "adductors", secondary: ["hip_flexors"] },

  // Shared: Copenhagen Plank (in knee-hip as -b, core-stability as -d)
  "copenhagen-plank":          { type: "duration", equip: "none", muscle: "abdominals", secondary: ["adductors"] },

  // Ankle & Integration
  "extended-ankle-cars":       { type: "reps_only", equip: "none", muscle: "calves", secondary: [] },
  "eccentric-calf-raises":     { type: "reps_only", equip: "none", muscle: "calves", secondary: [] },
  "wall-dorsiflexion":         { type: "duration", equip: "none", muscle: "calves", secondary: [] },
  "single-leg-balance":        { type: "duration", equip: "none", muscle: "calves", secondary: ["glutes"] },
  "supported-deep-squat":      { type: "duration", equip: "none", muscle: "quadriceps", secondary: ["glutes", "calves"] },
  "bear-crawl":                { type: "duration", equip: "none", muscle: "shoulders", secondary: ["abdominals", "quadriceps"] },

  // Shared: Dead Bugs (in ankle-integration as -c, core-stability as -d)
  "dead-bugs":                 { type: "reps_only", equip: "none", muscle: "abdominals", secondary: ["hip_flexors"] },

  // Core Stability
  "pallof-press":              { type: "reps_only", equip: "resistance_band", muscle: "abdominals", secondary: ["obliques"] },
  "bird-dogs":                 { type: "reps_only", equip: "none", muscle: "lower_back", secondary: ["abdominals", "glutes"] },
  "suitcase-carry":            { type: "duration", equip: "dumbbell", muscle: "abdominals", secondary: ["forearms", "obliques"] },

  // Active Recovery
  "stationary-bike":           { type: "duration", equip: "machine", muscle: "quadriceps", secondary: ["calves", "glutes"] },
  "foam-roll-quads":           { type: "duration", equip: "foam_roller", muscle: "quadriceps", secondary: [] },
  "foam-roll-calves":          { type: "duration", equip: "foam_roller", muscle: "calves", secondary: [] },
  "lacrosse-ball-shoulder":    { type: "duration", equip: "other", muscle: "shoulders", secondary: ["upper_back"] },
};

// в”Җв”Җ Step 2: Merge duplicates map в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
// Maps suffixed IDs to canonical IDs
const canonicalId = {
  "hollow-body-hold-a": "hollow-body-hold",
  "hollow-body-hold-d": "hollow-body-hold",
  "copenhagen-plank-b": "copenhagen-plank",
  "copenhagen-plank-d": "copenhagen-plank",
  "dead-bugs-c":        "dead-bugs",
  "dead-bugs-d":        "dead-bugs",
};

// в”Җв”Җ Step 3: Extract exercise templates в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
const templateMap = new Map(); // canonical id вҶ’ ExerciseTemplate

for (const session of program.sessions) {
  for (const ex of session.exercises) {
    const cid = canonicalId[ex.id] ?? ex.id;
    if (templateMap.has(cid)) continue; // first occurrence wins for defaults

    const meta = exerciseMeta[cid];
    if (!meta) {
      console.error(`Missing metadata for exercise: ${cid} (original: ${ex.id})`);
      process.exit(1);
    }

    const template = {
      id: cid,
      title: ex.name,
      type: meta.type,
      equipmentCategory: meta.equip,
      primaryMuscleGroup: meta.muscle,
    };

    if (meta.secondary.length > 0) {
      template.secondaryMuscleGroups = meta.secondary;
    }

    // Coaching fields
    if (ex.notes) template.notes = ex.notes;
    if (ex.videoURL) template.videoURL = ex.videoURL;
    if (ex.searchTerms) template.searchTerms = ex.searchTerms;
    if (ex.tags && ex.tags.length > 0) template.tags = ex.tags;
    if (ex.progressionByPhase) template.progressionByPhase = ex.progressionByPhase;

    templateMap.set(cid, template);
  }
}

// For merged exercises, also merge progressionByPhase and tags from all occurrences
for (const session of program.sessions) {
  for (const ex of session.exercises) {
    const cid = canonicalId[ex.id] ?? ex.id;
    const template = templateMap.get(cid);

    // Merge tags
    if (ex.tags && ex.tags.length > 0) {
      const existing = new Set(template.tags ?? []);
      for (const t of ex.tags) existing.add(t);
      if (existing.size > 0) template.tags = [...existing];
    }

    // Merge progressionByPhase
    if (ex.progressionByPhase) {
      template.progressionByPhase = { ...(template.progressionByPhase ?? {}), ...ex.progressionByPhase };
    }
  }
}

const exerciseTemplates = [...templateMap.values()];

// в”Җв”Җ Step 4: Convert sessions to routines в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
const routines = program.sessions.map((session) => {
  const routine = {
    id: session.id,
    title: session.title,
  };
  if (session.subtitle) routine.subtitle = session.subtitle;
  if (session.description) routine.description = session.description;
  if (session.isDaily) routine.isDaily = true;
  if (session.sortOrder != null) routine.sortOrder = session.sortOrder;
  if (session.color) routine.color = session.color;

  routine.exercises = session.exercises.map((ex) => {
    const cid = canonicalId[ex.id] ?? ex.id;
    const ref = { exerciseTemplateId: cid };

    // Sets is required вҖ” use the sets from this specific routine context
    if (typeof ex.sets === "string") {
      ref.sets = ex.sets;
    } else if (typeof ex.sets === "number") {
      ref.sets = `${ex.sets} sets`;
    } else {
      ref.sets = "1 set";
    }

    // Notes override: only include if different from template default
    const template = templateMap.get(cid);
    if (ex.notes && template && ex.notes !== template.notes) {
      ref.notes = ex.notes;
    }

    return ref;
  });

  return routine;
});

// в”Җв”Җ Step 5: Update weekTemplates (sessionIDs вҶ’ routineIDs) в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
const weekTemplates = program.weekTemplates.map((wt) => ({
  ...wt,
  days: wt.days.map((day) => {
    const { sessionIDs, ...rest } = day;
    return { ...rest, routineIDs: sessionIDs ?? [] };
  }),
}));

// в”Җв”Җ Step 6: Assemble new program в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
const newProgram = {
  meta: program.meta,
  exerciseTemplates,
  routines,
  weekTemplates,
  progressions: program.progressions,
  roadmap: program.roadmap,
  skills: program.skills,
  benchmarks: program.benchmarks,
  foundations: program.foundations,
  theme: program.theme,
};

// в”Җв”Җ Step 7: Write output в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
writeFileSync(inputPath, JSON.stringify(newProgram, null, 2) + "\n");

console.log(`Wrote ${exerciseTemplates.length} exercise templates, ${routines.length} routines`);
console.log("Merged duplicates:", Object.entries(canonicalId).map(([k, v]) => `${k} вҶ’ ${v}`).join(", "));

