 57вҶ’/** Find the active progression based on start_date and current date. */
 58вҶ’function getCurrentProgression(
 59вҶ’  startDate: string,
 60вҶ’  progressions: Progression[]
 61вҶ’): Progression | undefined {
 62вҶ’  const start = new Date(startDate);
 63вҶ’  const now = new Date();
 64вҶ’  const diffMs = now.getTime() - start.getTime();
 65вҶ’  const currentWeek = Math.floor(diffMs / (7 * 24 * 60 * 60 * 1000)) + 1;
 66вҶ’
 67вҶ’  return progressions.find(
 68вҶ’    (p) =>
 69вҶ’      p.weekStart != null &&
 70вҶ’      p.weekEnd != null &&
 71вҶ’      currentWeek >= p.weekStart &&
 72вҶ’      currentWeek <= p.weekEnd
 73вҶ’  );
 74вҶ’}
