387вҶ’
388вҶ’  // Get or auto-create exercise template mappings
389вҶ’  let mappings = await getExerciseTemplateMappings(env.DB, userId);
390вҶ’  if (mappings.length === 0) {
391вҶ’    // First push: auto-match exercise templates
392вҶ’    try {
393вҶ’      const hevyTemplates = await client.getAllExerciseTemplates();
394вҶ’      const autoMatched = autoMatchExercises(program.exerciseTemplates, hevyTemplates);
395вҶ’
396вҶ’      for (const [programTemplateId, hevyTemplateId] of autoMatched) {
397вҶ’        await upsertExerciseTemplateMapping(env.DB, {
398вҶ’          user_id: userId,
399вҶ’          program_template_id: programTemplateId,
400вҶ’          hevy_template_id: hevyTemplateId,
401вҶ’          is_custom: 0,
402вҶ’        });
403вҶ’      }
404вҶ’      mappings = await getExerciseTemplateMappings(env.DB, userId);
405вҶ’    } catch {
406вҶ’      // If auto-match fails, continue with empty mappings
407вҶ’    }
408вҶ’  }
409вҶ’
410вҶ’  const payload = buildRoutinePayload(session, mappings);
411вҶ’
412вҶ’  try {
413вҶ’    // Find existing queue item to update
414вҶ’    const items = await getQueueItems(env.DB, userId);
415вҶ’    const queueItem = items.find(
416вҶ’      (i) => i.routine_id === sessionId && i.status === "pending"
417вҶ’    );
418вҶ’
419вҶ’    let routineId: string;
420вҶ’    if (queueItem?.hevy_routine_id) {
421вҶ’      // Update existing routine
422вҶ’      const routine = await client.updateRoutine(queueItem.hevy_routine_id, {
423вҶ’        title: payload.title,
424вҶ’        exercises: payload.exercises,
425вҶ’      });
426вҶ’      routineId = routine.id;
427вҶ’    } else {
428вҶ’      // Create new routine
429вҶ’      const routine = await client.createRoutine({
430вҶ’        title: payload.title,
431вҶ’        exercises: payload.exercises,
432вҶ’      });
433вҶ’      routineId = routine.id;
434вҶ’    }
435вҶ’
436вҶ’    // Store routine ID on queue item
437вҶ’    if (queueItem) {
438вҶ’      await updateQueueItemHevyRoutineId(env.DB, queueItem.id, routineId);
439вҶ’    }
440вҶ’
441вҶ’    const unmappedNote =
442вҶ’      payload.unmapped.length > 0
443вҶ’        ? `<p style="color:var(--orange);font-size:13px;margin-top:8px">${payload.unmapped.length} exercise(s) could not be mapped.</p>`
444вҶ’        : "";
445вҶ’
446вҶ’    return sseResponse(
447вҶ’      patchElements(
448вҶ’        `<div class="card"><p style="color:var(--green)">Pushed to Hevy!</p>${unmappedNote}</div>`,
449вҶ’        { selector: "#content", mode: "prepend" }
450вҶ’      )
451вҶ’    );
452вҶ’  } catch (err) {
453вҶ’    const msg = escapeHtml(err instanceof Error ? err.message : "Push failed");
454вҶ’    return sseResponse(
455вҶ’      patchElements(
456вҶ’        `<div class="card"><p style="color:var(--orange)">${msg}</p></div>`,
457вҶ’        { selector: "#content", mode: "prepend" }
458вҶ’      )
459вҶ’    );
460вҶ’  }
461вҶ’}
462вҶ’
463вҶ’/** POST /api/pull вҖ” pull completions from Hevy */
464вҶ’async function handlePull(env: Env, userId: string): Promise<Response> {
465вҶ’  const user = await getUser(env.DB, userId);
466вҶ’  if (!user || !user.hevy_api_key) {
467вҶ’    return sseResponse(
468вҶ’      patchElements(`<div class="card"><p>Connect your Hevy API key first.</p></div>`, {
469вҶ’        selector: "#content",
470вҶ’        mode: "inner",
471вҶ’      })
472вҶ’    );
473вҶ’  }
474вҶ’
475вҶ’  const client = new HevyClient(user.hevy_api_key);
476вҶ’
477вҶ’  try {
478вҶ’    const workouts = await client.getRecentWorkouts();
479вҶ’    const items = await getQueueItems(env.DB, userId);
480вҶ’    const pendingItems = items.filter((i) => i.status === "pending" && i.hevy_routine_id);
481вҶ’
482вҶ’    // Build a nameвҶ’routine_id lookup from pending items
483вҶ’    const nameToRoutineId = new Map<string, string>();
484вҶ’    for (const item of pendingItems) {
485вҶ’      const routine = program.routines.find((r) => r.id === item.routine_id);
486вҶ’      if (routine && item.hevy_routine_id) {
487вҶ’        nameToRoutineId.set(routine.title, item.hevy_routine_id);
488вҶ’      }
489вҶ’    }
490вҶ’
491вҶ’    const matches = matchCompletions(
492вҶ’      pendingItems,
493вҶ’      workouts,
494вҶ’      (w) => nameToRoutineId.get(w.name) ?? null
495вҶ’    );
496вҶ’
497вҶ’    const today = todayString();
498вҶ’    for (const match of matches) {
499вҶ’      await markQueueItemCompleted(env.DB, match.queueItemId, today, match.workoutId);
500вҶ’    }
501вҶ’
502вҶ’    // Re-render today page
503вҶ’    return await handleTodaySSE(env, userId);
504вҶ’  } catch (err) {
505вҶ’    const msg = escapeHtml(err instanceof Error ? err.message : "Pull failed");
506вҶ’    return sseResponse(
507вҶ’      patchElements(
508вҶ’        `<div class="card"><p style="color:var(--orange)">${msg}</p></div>`,
509вҶ’        { selector: "#content", mode: "prepend" }
510вҶ’      )
511вҶ’    );
512вҶ’  }
513вҶ’}
514вҶ’
515вҶ’/** POST /api/complete/:id вҖ” manual complete, re-render today */
516вҶ’async function handleManualComplete(
517вҶ’  env: Env,
518вҶ’  userId: string,
519вҶ’  itemId: number
520вҶ’): Promise<Response> {
521вҶ’  if (!Number.isInteger(itemId)) {
522вҶ’    return new Response("Invalid item ID", { status: 400 });
523вҶ’  }
524вҶ’  const today = todayString();
525вҶ’  await markQueueItemCompletedForUser(env.DB, itemId, userId, today);
526вҶ’  return await handleTodaySSE(env, userId);
527вҶ’}
