  6вҶ’// в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
  7вҶ’
  8вҶ’/**
  9вҶ’ * Parse a sets string like "3Г—8", "3Г—30 sec", "2Г—45 sec", "3Г—1 min"
 10вҶ’ * into an array of HevySet objects.
 11вҶ’ *
 12вҶ’ * - Patterns containing "sec" or "min" produce duration_seconds sets.
 13вҶ’ * - All other patterns produce reps sets.
 14вҶ’ */
 15вҶ’function parseSetsString(setsStr: string): HevySet[] {
 16вҶ’  // Normalise the multiplication sign вҖ” programs may use Г— (U+00D7) or x
 17вҶ’  const normalised = setsStr.replace(/Г—/g, "x");
 18вҶ’
 19вҶ’  // Match "NxM sec", "NxM min", or "NxM"
 20вҶ’  const match = normalised.match(/^(\d+)\s*x\s*(\d+(?:\.\d+)?)\s*(sec|min)?/i);
 21вҶ’  if (!match) {
 22вҶ’    // Fallback: return a single normal set with no values
 23вҶ’    return [{ type: "normal", reps: null, repRange: { start: null, end: null } }];
 24вҶ’  }
 25вҶ’
 26вҶ’  const count = parseInt(match[1], 10);
 27вҶ’  const value = parseFloat(match[2]);
 28вҶ’  const unit = match[3]?.toLowerCase();
 29вҶ’
 30вҶ’  const isDuration = unit === "sec" || unit === "min";
 31вҶ’  const duration_seconds = isDuration
 32вҶ’    ? unit === "min"
 33вҶ’      ? Math.round(value * 60)
 34вҶ’      : Math.round(value)
 35вҶ’    : undefined;
 36вҶ’
 37вҶ’  const sets: HevySet[] = [];
 38вҶ’  for (let i = 0; i < count; i++) {
 39вҶ’    if (isDuration) {
 40вҶ’      sets.push({ type: "normal", reps: null, repRange: { start: null, end: null }, duration_seconds });
 41вҶ’    } else {
 42вҶ’      const reps = Math.round(value);
 43вҶ’      sets.push({ type: "normal", reps, repRange: { start: reps, end: reps } });
 44вҶ’    }
 45вҶ’  }
 46вҶ’  return sets;
 47вҶ’}
 48вҶ’
 49вҶ’// в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
 50вҶ’// buildRoutinePayload
 51вҶ’// в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
 52вҶ’
 53вҶ’export interface RoutinePayload {
 54вҶ’  title: string;
 55вҶ’  exercises: HevyRoutineExercise[];
 56вҶ’  /** Exercise template IDs from the routine that had no mapping */
 57вҶ’  unmapped: string[];
 58вҶ’}
 59вҶ’
 60вҶ’/**
 61вҶ’ * Build a Hevy routine payload from a program routine + exercise template mappings.
 62вҶ’ * Exercises without a mapping are collected in `unmapped` and omitted from
 63вҶ’ * the payload.
 64вҶ’ */
 65вҶ’export function buildRoutinePayload(
 66вҶ’  routine: Routine,
 67вҶ’  mappings: ExerciseTemplateMappingRow[]
 68вҶ’): RoutinePayload {
 69вҶ’  const mappingMap = new Map(
 70вҶ’    mappings.map((m) => [m.program_template_id, m.hevy_template_id])
 71вҶ’  );
 72вҶ’
 73вҶ’  const exercises: HevyRoutineExercise[] = [];
 74вҶ’  const unmapped: string[] = [];
 75вҶ’
 76вҶ’  for (const exercise of routine.exercises) {
 77вҶ’    const hevyId = mappingMap.get(exercise.exerciseTemplateId);
 78вҶ’    if (!hevyId) {
 79вҶ’      unmapped.push(exercise.exerciseTemplateId);
 80вҶ’      continue;
 81вҶ’    }
 82вҶ’
 83вҶ’    const sets = parseSetsString(exercise.sets);
 84вҶ’
 85вҶ’    exercises.push({
 86вҶ’      exercise_template_id: hevyId,
 87вҶ’      sets,
 88вҶ’      notes: exercise.notes,
 89вҶ’    });
 90вҶ’  }
 91вҶ’
 92вҶ’  return { title: routine.title, exercises, unmapped };
 93вҶ’}
 94вҶ’
 95вҶ’// в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
 96вҶ’// matchCompletions
 97вҶ’// в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
 98вҶ’
 99вҶ’export interface CompletionMatch {
100вҶ’  queueItemId: number;
101вҶ’  workoutId: string;
102вҶ’}
103вҶ’
104вҶ’/**
105вҶ’ * Match Hevy workouts to queue items by comparing each workout's routine ID
106вҶ’ * (obtained via `getRoutineId`) to the `hevy_routine_id` stored on the queue
107вҶ’ * item.
108вҶ’ *
109вҶ’ * Each workout is matched to at most one queue item.
110вҶ’ */
111вҶ’export function matchCompletions(
112вҶ’  items: Pick<QueueItemRow, "id" | "hevy_routine_id">[],
113вҶ’  workouts: HevyWorkout[],
114вҶ’  getRoutineId: (workout: HevyWorkout) => string | null
115вҶ’): CompletionMatch[] {
116вҶ’  // Build a map: routine_id вҶ’ queue item id
117вҶ’  const routineToItem = new Map<string, number>();
118вҶ’  for (const item of items) {
119вҶ’    if (item.hevy_routine_id) {
120вҶ’      routineToItem.set(item.hevy_routine_id, item.id);
121вҶ’    }
122вҶ’  }
123вҶ’
124вҶ’  const matches: CompletionMatch[] = [];
125вҶ’  const usedItems = new Set<number>();
126вҶ’
127вҶ’  for (const workout of workouts) {
128вҶ’    const routineId = getRoutineId(workout);
129вҶ’    if (!routineId) continue;
130вҶ’
131вҶ’    const itemId = routineToItem.get(routineId);
132вҶ’    if (itemId !== undefined && !usedItems.has(itemId)) {
133вҶ’      matches.push({ queueItemId: itemId, workoutId: workout.id });
134вҶ’      usedItems.add(itemId);
135вҶ’    }
136вҶ’  }
137вҶ’
138вҶ’  return matches;
139вҶ’}
140вҶ’
141вҶ’// в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
142вҶ’// autoMatchExercises
143вҶ’// в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
144вҶ’
145вҶ’/**
146вҶ’ * Normalize an exercise name for fuzzy matching:
147вҶ’ * - Lowercase
148вҶ’ * - Strip non-alphanumeric characters (spaces, hyphens, punctuation)
149вҶ’ * - Strip a trailing 's' (basic singular/plural normalisation)
150вҶ’ */
151вҶ’function normalizeName(name: string): string {
152вҶ’  return name
153вҶ’    .toLowerCase()
154вҶ’    .replace(/[^a-z0-9]/g, "")
155вҶ’    .replace(/s$/, "");
156вҶ’}
157вҶ’
158вҶ’/**
159вҶ’ * Attempt to automatically match our exercise templates to Hevy exercise
160вҶ’ * template IDs using normalized title comparison. Supports partial matching
161вҶ’ * (one normalized name contains the other).
162вҶ’ *
163вҶ’ * Returns a Map of our template ID вҶ’ Hevy template ID for every template
164вҶ’ * that could be matched.
165вҶ’ */
166вҶ’export function autoMatchExercises(
167вҶ’  ourTemplates: ExerciseTemplate[],
168вҶ’  hevyTemplates: HevyExerciseTemplate[]
169вҶ’): Map<string, string> {
170вҶ’  const result = new Map<string, string>();
171вҶ’
172вҶ’  // Pre-normalize Hevy template titles
173вҶ’  const normalizedHevy = hevyTemplates.map((t) => ({
174вҶ’    id: t.id,
175вҶ’    norm: normalizeName(t.title),
176вҶ’  }));
177вҶ’
178вҶ’  for (const template of ourTemplates) {
179вҶ’    const normOurs = normalizeName(template.title);
180вҶ’
181вҶ’    // Prefer exact match first
182вҶ’    let matched = normalizedHevy.find((t) => t.norm === normOurs);
183вҶ’
184вҶ’    // Fall back to partial match (one contains the other)
185вҶ’    if (!matched) {
186вҶ’      matched = normalizedHevy.find(
187вҶ’        (t) => t.norm.includes(normOurs) || normOurs.includes(t.norm)
188вҶ’      );
189вҶ’    }
190вҶ’
191вҶ’    if (matched) {
192вҶ’      result.set(template.id, matched.id);
193вҶ’    }
194вҶ’  }
195вҶ’
196вҶ’  return result;
197вҶ’}
198вҶ’

