// в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
// Progress page fragments вҖ” skills, roadmap, benchmarks
// в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

import type { Skill, RoadmapPhase, Benchmark } from "../types";

/**
 * Skill cards вҖ” expandable cards with icon, name, timeline, priority badge.
 * The first card is expanded by default; others are collapsed.
 * Uses Datastar signals for expand/collapse toggling.
 */
export function skillCards(skills: Skill[]): string {
  if (skills.length === 0) return "";

  const cards = skills.map((skill, index) => {
    const expanded = index === 0;
    const signalName = `skill_${skill.id.replace(/[^a-zA-Z0-9]/g, "_")}`;
    const iconBg = skill.color ? `background:${skill.color}22` : "background:rgba(255,255,255,0.06)";
    const iconColor = skill.color ?? "var(--text)";
    const priorityLabel = skill.priority != null ? `#${skill.priority}` : "";

    const milestonesHtml =
      skill.milestones && skill.milestones.length > 0
        ? `<ul class="milestone-list">${skill.milestones
            .map(
              (m) =>
                `<li class="milestone-item">
  <div class="milestone-dot" style="background:${skill.color ?? "var(--blue)"}"></div>
  <div>
    <div class="milestone-name">${escapeHtml(m.name)}</div>
    ${m.description ? `<div class="milestone-desc">${escapeHtml(m.description)}</div>` : ""}
    ${m.targetWeek != null ? `<div class="milestone-week">Week ${m.targetWeek}</div>` : ""}
  </div>
</li>`
            )
            .join("")}</ul>`
        : "";

    return `<div class="skill-card" data-signals:${signalName}="${expanded}">
  <div class="skill-header" data-on:click="$${signalName} = !$${signalName}">
    <div class="skill-icon" style="${iconBg}; color:${iconColor}">${escapeHtml(skill.icon ?? "")}</div>
    <span class="skill-name">${escapeHtml(skill.name)}</span>
    ${priorityLabel ? `<span class="skill-priority">${escapeHtml(priorityLabel)}</span>` : ""}
  </div>
  <div class="skill-body" data-show="$${signalName}">
    ${skill.timeline ? `<div class="skill-timeline">${escapeHtml(skill.timeline)}</div>` : ""}
    ${milestonesHtml}
  </div>
</div>`;
  });

  return `<div class="section-header">Skills</div>\n${cards.join("\n")}`;
}

/**
 * Roadmap section вҖ” static phase list with current phase highlighted.
 */
export function roadmapSection(phases: RoadmapPhase[]): string {
  if (phases.length === 0) return "";

  const sorted = [...phases].sort((a, b) => (a.sortOrder ?? 0) - (b.sortOrder ?? 0));

  const items = sorted
    .map((phase) => {
      const isCurrent = phase.status === "current";
      const isCompleted = phase.status === "completed";
      const cls = isCurrent ? " roadmap-current" : "";
      const dotColor = isCurrent
        ? "var(--blue)"
        : isCompleted
          ? "var(--green)"
          : "var(--text-tertiary)";

      return `<div class="roadmap-item${cls}">
  <div class="roadmap-indicator" style="background:${dotColor}"></div>
  <div>
    <div class="roadmap-name">${escapeHtml(phase.name)}</div>
    ${phase.weeks ? `<div class="roadmap-weeks">${escapeHtml(phase.weeks)}</div>` : ""}
    ${phase.summary ? `<div class="roadmap-summary">${escapeHtml(phase.summary)}</div>` : ""}
  </div>
</div>`;
    })
    .join("\n");

  return `<div class="section-header">Roadmap</div>
<div class="card">
${items}
</div>`;
}

/**
 * Benchmarks section вҖ” static list with name, target, how-to.
 */
export function benchmarksSection(benchmarks: Benchmark[]): string {
  if (benchmarks.length === 0) return "";

  const items = benchmarks
    .map(
      (b) =>
        `<div class="benchmark-item">
  <div class="benchmark-name">${escapeHtml(b.name)}</div>
  ${b.target ? `<div class="benchmark-target">${escapeHtml(b.target)}</div>` : ""}
  <div class="benchmark-howto">${escapeHtml(b.howTo)}</div>
</div>`
    )
    .join("\n");

  return `<div class="section-header">Benchmarks</div>
<div class="card">
${items}
</div>`;
}

// в”Җв”Җ Helpers в”Җв”Җ

function escapeHtml(str: string): string {
  return str
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;")
    .replace(/"/g, "&quot;");
}

// в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
// Setup page вҖ” first-run: API key, start date, template selection
// в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

import type { WeekTemplate } from "../types";

/**
 * First-run setup page. Collects:
 * - Hevy API key (password field)
 * - Start date (date picker, defaults to today)
 * - Week template selection (clicking a card submits the form)
 *
 * The form POSTs to /api/setup with { apiKey, startDate, templateId }.
 */
export function setupPage(templates: WeekTemplate[]): string {
  // Default date is set client-side to avoid UTC/local timezone mismatch
  const today = "";

  const sorted = [...templates].sort(
    (a, b) => (a.sortOrder ?? 0) - (b.sortOrder ?? 0)
  );

  const templateCards = sorted
    .map(
      (t) =>
        `<div class="template-card" data-on:click="@post('/api/setup/${escapeAttr(t.id)}')">
  <div class="template-name">${escapeHtml(t.name)}</div>
  ${t.description ? `<div class="template-desc">${escapeHtml(t.description)}</div>` : ""}
</div>`
    )
    .join("\n    ");

  return `<div class="setup-container" data-signals:api-key="''" data-signals:start-date="new Date().toLocaleDateString('en-CA')" data-signals:template-id="''">
  <div style="text-align:center; margin-bottom:32px">
    <h2 class="card-title" style="font-size:24px">Welcome</h2>
    <p class="card-subtitle" style="margin-top:4px">Connect your Hevy account and pick a schedule.</p>
  </div>

  <div class="form-group">
    <label class="form-label" for="apiKey">Hevy API Key</label>
    <input
      id="apiKey"
      type="password"
      class="form-input"
      placeholder="Enter your Hevy API key"
      autocomplete="off"
      data-bind:api-key
    />
  </div>

  <div class="form-group">
    <label class="form-label" for="startDate">Start Date</label>
    <input
      id="startDate"
      type="date"
      class="form-input"
      data-bind:start-date
    />
  </div>

  <div class="form-group">
    <label class="form-label">Choose Your Schedule</label>
    <div class="template-grid">
    ${templateCards}
    </div>
  </div>
</div>`;
}

// в”Җв”Җ Helpers в”Җв”Җ

function escapeHtml(str: string): string {
  return str
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;")
    .replace(/"/g, "&quot;");
}

function escapeAttr(str: string): string {
  return str.replace(/[&<>"']/g, (c) => {
    switch (c) {
      case "&": return "&amp;";
      case "<": return "&lt;";
      case ">": return "&gt;";
      case '"': return "&quot;";
      case "'": return "&#39;";
      default: return c;
    }
  });
}

