.tab-icon {
  width: 24px;
  height: 24px;
}

.tab-label {
  font-size: 10px;
}

/* в”Җв”Җ Separators в”Җв”Җ */
.separator {
  height: 1px;
  background: var(--separator);
  margin: 12px 0;
}

/* в”Җв”Җ Completed items в”Җв”Җ */
.completed-item {
  display: flex;
  align-items: center;
  gap: 10px;
  padding: 10px 0;
