}

.upcoming-title {
  font-size: 15px;
  flex: 1;
}

.upcoming-count {
  font-size: 13px;
  color: var(--text-tertiary);
}

.upcoming-spacer .upcoming-title {
  color: var(--text-tertiary);
  font-style: italic;
}

/* в”Җв”Җ Exercise list в”Җв”Җ */
.exercise-item {
  padding: 14px 0;
}

.exercise-item + .exercise-item {
  border-top: 1px solid var(--separator);
}

.exercise-header {
  display: flex;
  align-items: baseline;
