  gap: 4px;
  font-size: 13px;
  color: var(--blue);
  text-decoration: none;
  margin: 6px 0 0 28px;
}

.exercise-tags {
  display: flex;
  gap: 6px;
  margin: 6px 0 0 28px;
  flex-wrap: wrap;
}

.exercise-tag {
  font-size: 11px;
  font-weight: 600;
  color: var(--purple);
  background: rgba(191,90,242,0.12);
  padding: 2px 8px;
  border-radius: 6px;
}

/* в”Җв”Җ Phase coaching callout в”Җв”Җ */
.coaching-callout {
  background: rgba(255,159,10,0.08);
  border-radius: var(--radius);
  padding: 14px 16px;
  margin-bottom: 16px;
}

.coaching-label {
  font-size: 11px;
  font-weight: 700;
  text-transform: uppercase;
  letter-spacing: 0.8px;
  color: var(--orange);
  margin-bottom: 6px;
}

.coaching-focus {
  font-size: 14px;
