  gap: 10px;
  padding: 14px 16px;
  cursor: pointer;
}

.skill-icon {
  font-size: 20px;
  width: 32px;
  height: 32px;
  display: flex;
  align-items: center;
  justify-content: center;
  border-radius: 8px;
  flex-shrink: 0;
}

.skill-name {
  font-size: 16px;
  font-weight: 600;
  flex: 1;
}

.skill-priority {
  font-size: 11px;
  font-weight: 700;
  color: var(--text-tertiary);
  background: rgba(255,255,255,0.06);
  padding: 2px 8px;
  border-radius: 6px;
}

.skill-body {
  padding: 0 16px 16px;
}

.skill-timeline {
  font-size: 13px;
  color: var(--text-secondary);
  margin-bottom: 12px;
}

.milestone-list {
  list-style: none;
}

.milestone-item {
  display: flex;
  gap: 10px;
  padding: 8px 0;
}

.milestone-item + .milestone-item {
  border-top: 1px solid var(--separator);
