.milestone-dot {
  width: 8px;
  height: 8px;
  border-radius: 50%;
  margin-top: 5px;
  flex-shrink: 0;
}

.milestone-name {
  font-size: 14px;
  font-weight: 600;
}

.milestone-desc {
  font-size: 13px;
  color: var(--text-secondary);
}

.milestone-week {
  font-size: 12px;
  color: var(--text-tertiary);
}

/* в”Җв”Җ Roadmap в”Җв”Җ */
.roadmap-item {
  display: flex;
  gap: 12px;
  padding: 14px 0;
}

.roadmap-item + .roadmap-item {
  border-top: 1px solid var(--separator);
}

.roadmap-indicator {
  width: 10px;
  height: 10px;
  border-radius: 50%;
  margin-top: 4px;
  flex-shrink: 0;
}

.roadmap-name {
  font-size: 15px;
  font-weight: 600;
}

.roadmap-weeks {
  font-size: 13px;
  color: var(--text-secondary);
  margin-top: 2px;
}

.roadmap-summary {
  font-size: 13px;
  color: var(--text-secondary);
  line-height: 1.45;
  margin-top: 4px;
}

.roadmap-current .roadmap-name {
  color: var(--green);
}

/* в”Җв”Җ Benchmarks в”Җв”Җ */
.benchmark-item {
  padding: 14px 0;
}

.benchmark-item + .benchmark-item {
  border-top: 1px solid var(--separator);
}

.benchmark-name {
  font-size: 15px;
  font-weight: 600;
}

.benchmark-target {
  font-size: 13px;
  color: var(--blue);
  margin-top: 2px;
}

.benchmark-howto {
  font-size: 13px;
  color: var(--text-secondary);
  line-height: 1.45;
  margin-top: 4px;
}

/* в”Җв”Җ Setup page в”Җв”Җ */
.setup-container {
  max-width: 480px;
  margin: 0 auto;
}

.form-group {
  margin-bottom: 20px;
}

.form-label {
  display: block;
  font-size: 13px;
  font-weight: 600;
  color: var(--text-secondary);
  text-transform: uppercase;
  letter-spacing: 0.5px;
  margin-bottom: 8px;
}

.form-input {
  width: 100%;
  padding: 12px 14px;
  font-size: 16px;
  font-family: inherit;
  background: var(--card);
  color: var(--text);
  border: 1px solid var(--separator);
  border-radius: var(--radius);
  outline: none;
  transition: border-color 0.15s;
}

.form-input:focus {
  border-color: var(--blue);
}

.template-grid {
  display: grid;
  gap: 12px;
}

.template-card {
  background: var(--card);
  border-radius: var(--radius);
  padding: 16px;
  cursor: pointer;
  transition: background 0.15s, box-shadow 0.15s;
  border: 1px solid transparent;
}

.template-card:hover {
  background: #2C2C2E;
}

.template-card:active {
  background: #3A3A3C;
}

.template-name {
  font-size: 16px;
  font-weight: 600;
}

.template-desc {
  font-size: 13px;
  color: var(--text-secondary);
  line-height: 1.4;
  margin-top: 4px;
}
`;

