function todayString(): string {
  return new Date().toISOString().slice(0, 10);
}

/** Find the active progression based on start_date and current date. */
function getCurrentProgression(
  startDate: string,
  progressions: Progression[]
): Progression | undefined {
  const start = new Date(startDate);
  const now = new Date();
  const diffMs = now.getTime() - start.getTime();
  const currentWeek = Math.floor(diffMs / (7 * 24 * 60 * 60 * 1000)) + 1;

  return progressions.find(
    (p) =>
      p.weekStart != null &&
      p.weekEnd != null &&
      currentWeek >= p.weekStart &&
      currentWeek <= p.weekEnd
  );
}

function htmlResponse(body: string): Response {
  return new Response(body, {
    headers: { "content-type": "text/html; charset=utf-8" },
  });
}

function jsonResponse(data: unknown, status = 200): Response {
  return new Response(JSON.stringify(data), {
    status,
    headers: { "content-type": "application/json" },
  });
}

function redirect(location: string, status = 303): Response {
  return new Response(null, { status, headers: { location } });
}

// в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
// Router
// в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

export default {
  async fetch(request: Request, env: Env): Promise<Response> {
    try {
      const auth = getAuthenticatedUserOrDev(request, env);
      const url = new URL(request.url);
      const path = url.pathname;
      const method = request.method;

      // в”Җв”Җ GET / в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
      if (method === "GET" && path === "/") {
        const user = await getUser(env.DB, auth.userId);
        if (!user) {
          return htmlResponse(
            htmlShell({
              title: APP_NAME,
              subtitle: "Setup",
              body: `<div id="content">${setupPage(program.weekTemplates)}</div>`,
            })
          );
        }

        if (isSSERequest(request)) {
          return await handleTodaySSE(env, auth.userId);
        }

        return htmlResponse(
          htmlShell({
            title: APP_NAME,
            subtitle: program.meta.subtitle,
            activeTab: "today",
            ssePath: "/",
          })
        );
      }

      // в”Җв”Җ GET /progress в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
      if (method === "GET" && path === "/progress") {
        if (isSSERequest(request)) {
          return handleProgressSSE();
        }

        return htmlResponse(
          htmlShell({
            title: "Progress",
            subtitle: program.meta.subtitle,
            activeTab: "progress",
            ssePath: "/progress",
          })
        );
      }

      // в”Җв”Җ GET /routine/:id в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
      const routineMatch = path.match(/^\/routine\/([^/]+)$/);
      if (method === "GET" && routineMatch) {
        const routineId = decodeURIComponent(routineMatch[1]);

        if (isSSERequest(request)) {
          return await handleRoutineSSE(env, auth.userId, routineId);
        }

        return htmlResponse(
          htmlShell({
            title: "Routine",
            activeTab: "today",
            ssePath: `/routine/${encodeURIComponent(routineId)}`,
          })
        );
      }

      // в”Җв”Җ POST /api/setup/:templateId в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
      const setupMatch = path.match(/^\/api\/setup\/([^/]+)$/);
      if (method === "POST" && (path === "/api/setup" || setupMatch)) {
        const urlTemplateId = setupMatch ? decodeURIComponent(setupMatch[1]) : undefined;
        return await handleSetup(request, env, auth.userId, urlTemplateId);
      }

      // в”Җв”Җ POST /api/push-hevy/:id в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
      const pushMatch = path.match(/^\/api\/push-hevy\/([^/]+)$/);
      if (method === "POST" && pushMatch) {
        const routineId = decodeURIComponent(pushMatch[1]);
        return await handlePush(env, auth.userId, routineId);
      }

      // в”Җв”Җ POST /api/pull в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
      if (method === "POST" && path === "/api/pull") {
        return await handlePull(env, auth.userId);
      }

      // в”Җв”Җ POST /api/complete/:id в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
      const completeMatch = path.match(/^\/api\/complete\/([^/]+)$/);
      if (method === "POST" && completeMatch) {
        const itemId = parseInt(completeMatch[1], 10);
        return await handleManualComplete(env, auth.userId, itemId);
      }

      // в”Җв”Җ 404 в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
      return new Response("Not Found", { status: 404 });
    } catch (err) {
      if (err instanceof Response) return err;
      const message = err instanceof Error ? err.message : "Internal Server Error";
      return new Response(message, { status: 500 });
    }
  },
};

// в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
// Route handlers
// в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

/** SSE: Today page вҖ” CARs card, hero session, completed, upcoming */
async function handleTodaySSE(env: Env, userId: string): Promise<Response> {
  const user = await getUser(env.DB, userId);
  if (!user) {
    return sseResponse(
      patchElements(setupPage(program.weekTemplates), { selector: "#content", mode: "inner" })
    );
  }

  const items = await getQueueItems(env.DB, userId);
  const today = todayString();

  const fragments: string[] = [];

  if (dailyRoutine) {
    fragments.push(patchElements(carsCard(dailyRoutine), { selector: "#content", mode: "inner" }));
  }

  // Hero session card вҖ” next pending
  const nextItem = getNextRoutine(items);
  if (nextItem) {
    const routine = routineMap.get(nextItem.routine_id);
    if (routine) {
      fragments.push(
        patchElements(heroSessionCard(routine, nextItem), { selector: "#content", mode: "append" })
      );
    }
  }

  // Completed today
  const completed = getCompletedRoutines(items, today);
  if (completed.length > 0) {
    const completedData = completed.map((item) => ({
      title: routineMap.get(item.routine_id)?.title ?? item.routine_id,
    }));
    fragments.push(
      patchElements(completedSection(completedData), { selector: "#content", mode: "append" })
    );
  }

  // Upcoming (next 5 sessions)
  const template = program.weekTemplates.find((t) => t.id === user.template_id);
  if (template) {
    const pendingItems = items.filter((i) => i.status === "pending").sort((a, b) => a.position - b.position);
    // Skip the first pending (already shown as hero) for upcoming
    const upcomingPending = pendingItems.slice(1);
    const upcoming = computeUpcoming(upcomingPending, template, program.routines, 5);
    if (upcoming.length > 0) {
      fragments.push(
        patchElements(upcomingSection(upcoming), { selector: "#content", mode: "append" })
      );
    }
  }

  return sseResponse(mergeFragments(fragments));
}

/** SSE: Progress page вҖ” skills, roadmap, benchmarks */
function handleProgressSSE(): Response {
  const fragments: string[] = [];
  let isFirst = true;

  const addFragment = (html: string) => {
    fragments.push(patchElements(html, { selector: "#content", mode: isFirst ? "inner" : "append" }));
    isFirst = false;
  };

  if (program.skills && program.skills.length > 0) {
    addFragment(skillCards(program.skills));
  }

  if (program.roadmap && program.roadmap.length > 0) {
    addFragment(roadmapSection(program.roadmap));
  }

  if (program.benchmarks && program.benchmarks.length > 0) {
    addFragment(benchmarksSection(program.benchmarks));
  }

  return sseResponse(mergeFragments(fragments));
}

/** SSE: Routine detail вҖ” exercise list with coaching context */
async function handleRoutineSSE(env: Env, userId: string, routineId: string): Promise<Response> {
  const routine = program.routines.find((r) => r.id === routineId);
  if (!routine) {
    return sseResponse(
      patchElements(`<p>Routine not found.</p>`, { selector: "#content", mode: "inner" })
    );
  }

  // Look up user to determine current progression from start_date
  const user = await getUser(env.DB, userId);
  const currentProgression = user
    ? getCurrentProgression(user.start_date, program.progressions)
    : program.progressions[0];

  const html = routineDetailPage(routine, program.exerciseTemplates, currentProgression);
  return sseResponse(
    patchElements(html, { selector: "#content", mode: "inner" })
  );
}

/** POST /api/setup вҖ” create user, generate queue, navigate to today */
async function handleSetup(request: Request, env: Env, userId: string, urlTemplateId?: string): Promise<Response> {
  let body: { apiKey?: string; startDate?: string; templateId?: string } = {};
  try {
    body = await request.json() as typeof body;
  } catch {
    // Body may be empty вҖ” that's OK, template ID comes from URL
  }

  const templateId = urlTemplateId ?? body.templateId;
  const startDate = body.startDate || todayString();
  const apiKey = body.apiKey || undefined;

  if (!templateId) {
    return new Response("Template ID is required", { status: 400 });
  }

  const template = program.weekTemplates.find((t) => t.id === templateId);
  if (!template) {
    return new Response("Invalid template ID", { status: 400 });
  }

  // Validate API key against Hevy before proceeding
  if (apiKey) {
    try {
      const client = new HevyClient(apiKey);
      await client.getExerciseTemplates(1, 1);
    } catch {
      return sseResponse(
        patchElements(
          `<div class="card"><p style="color:var(--orange)">Invalid Hevy API key. Check your key in Hevy Settings &gt; Developer and try again.</p></div>`,
          { selector: "#content", mode: "prepend" }
        )
      );
    }
  }

  // Upsert user
  await upsertUser(env.DB, {
    id: userId,
    active_program: program.meta.title,
    template_id: templateId,
    start_date: startDate,
    hevy_api_key: apiKey,
  });

  // Generate queue playlist
  const weeks = program.meta.durationWeeks || 8;
  const playlist = generatePlaylist(template, program.routines, weeks);
  if (playlist.length > 0) {
    await insertQueueItems(env.DB, userId, playlist);
  }

  // Redirect to Today page via script injection (Datastar v1 pattern)
  return sseResponse(executeScript("window.location.href = '/'"));
}

/** POST /api/push-hevy/:id вҖ” push routine to Hevy */
async function handlePush(env: Env, userId: string, routineId: string): Promise<Response> {
  const user = await getUser(env.DB, userId);
  if (!user || !user.hevy_api_key) {
    return sseResponse(
      patchElements(`<div class="card"><p>Connect your Hevy API key first.</p></div>`, {
        selector: "#content",
        mode: "inner",
      })
    );
  }

  const routine = program.routines.find((r) => r.id === routineId);
  if (!routine) {
    return new Response("Routine not found", { status: 404 });
  }

  const client = new HevyClient(user.hevy_api_key);

  // Get or auto-create exercise template mappings
  let mappings = await getExerciseTemplateMappings(env.DB, userId);
  if (mappings.length === 0) {
    // First push: auto-match exercise templates
    try {
      const hevyTemplates = await client.getAllExerciseTemplates();
      const autoMatched = autoMatchExercises(program.exerciseTemplates, hevyTemplates);

      for (const [programTemplateId, hevyTemplateId] of autoMatched) {
        await upsertExerciseTemplateMapping(env.DB, {
          user_id: userId,
          program_template_id: programTemplateId,
          hevy_template_id: hevyTemplateId,
          is_custom: 0,
        });
      }
      mappings = await getExerciseTemplateMappings(env.DB, userId);
    } catch {
      // If auto-match fails, continue with empty mappings
    }
  }

  const payload = buildRoutinePayload(routine, mappings);

  try {
    // Find existing queue item to update
    const items = await getQueueItems(env.DB, userId);
    const queueItem = items.find(
      (i) => i.routine_id === routineId && i.status === "pending"
    );

    let hevyRoutineId: string;
    if (queueItem?.hevy_routine_id) {
      const updated = await client.updateRoutine(queueItem.hevy_routine_id, {
        title: payload.title,
        exercises: payload.exercises,
      });
      hevyRoutineId = updated.id;
    } else {
      const created = await client.createRoutine({
        title: payload.title,
        exercises: payload.exercises,
      });
      hevyRoutineId = created.id;
    }

    if (queueItem) {
      await updateQueueItemHevyRoutineId(env.DB, queueItem.id, hevyRoutineId);
    }

    const unmappedNote =
      payload.unmapped.length > 0
        ? `<p style="color:var(--orange);font-size:13px;margin-top:8px">${payload.unmapped.length} exercise(s) could not be mapped.</p>`
        : "";

    return sseResponse(
      patchElements(
        `<div class="card"><p style="color:var(--green)">Pushed to Hevy!</p>${unmappedNote}</div>`,
        { selector: "#content", mode: "prepend" }
      )
    );
  } catch (err) {
    const msg = escapeHtml(err instanceof Error ? err.message : "Push failed");
    return sseResponse(
      patchElements(
        `<div class="card"><p style="color:var(--orange)">${msg}</p></div>`,
        { selector: "#content", mode: "prepend" }
      )
    );
  }
}

/** POST /api/pull вҖ” pull completions from Hevy */
async function handlePull(env: Env, userId: string): Promise<Response> {
  const user = await getUser(env.DB, userId);
  if (!user || !user.hevy_api_key) {
    return sseResponse(
      patchElements(`<div class="card"><p>Connect your Hevy API key first.</p></div>`, {
        selector: "#content",
        mode: "inner",
      })
    );
  }

  const client = new HevyClient(user.hevy_api_key);

  try {
    const [workouts, items] = await Promise.all([
      client.getRecentWorkouts(),
      getQueueItems(env.DB, userId),
    ]);
    const pendingItems = items.filter((i) => i.status === "pending" && i.hevy_routine_id);

    const nameToRoutineId = new Map<string, string>();
    for (const item of pendingItems) {
      const routine = routineMap.get(item.routine_id);
      if (routine && item.hevy_routine_id) {
        nameToRoutineId.set(routine.title, item.hevy_routine_id);
      }
    }

    const matches = matchCompletions(
      pendingItems,
      workouts,
      (w) => nameToRoutineId.get(w.name) ?? null
    );

    const today = todayString();
    for (const match of matches) {
      await markQueueItemCompleted(env.DB, match.queueItemId, today, match.workoutId);
    }

    // Re-render today page
    return await handleTodaySSE(env, userId);
  } catch (err) {
    const msg = escapeHtml(err instanceof Error ? err.message : "Pull failed");
    return sseResponse(
      patchElements(
        `<div class="card"><p style="color:var(--orange)">${msg}</p></div>`,
        { selector: "#content", mode: "prepend" }
      )
    );
  }
}

/** POST /api/complete/:id вҖ” manual complete, re-render today */
async function handleManualComplete(
  env: Env,
  userId: string,
  itemId: number
): Promise<Response> {
  if (!Number.isInteger(itemId)) {
    return new Response("Invalid item ID", { status: 400 });
  }
  const today = todayString();
  await markQueueItemCompletedForUser(env.DB, itemId, userId, today);
  return await handleTodaySSE(env, userId);
}

// в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
// Today page fragments вҖ” CARs card, hero session, completed, upcoming
// в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

import type { Routine, QueueItemRow } from "../types";
import type { UpcomingItem } from "../domain/reflow";
import { escapeHtml, escapeAttr, truncate } from "../utils/html";

/**
 * Daily CARs card вҖ” always shown at the top of Today.
 * Green accent label, exercise count, Push to Hevy + Details.
 */
export function carsCard(routine: Routine): string {
  const count = routine.exercises.length;
  const subtitle = routine.subtitle ?? `${count} exercises`;

  return `<div class="card">
  <div class="card-label" style="color: var(--green)">Daily</div>
  <div class="card-title">${escapeHtml(routine.title)}</div>
  <div class="card-subtitle">${escapeHtml(subtitle)}</div>
  <div style="display:flex; gap:8px; margin-top:14px">
    <button class="btn btn-blue" data-on:click="@post('/api/push-hevy/daily')">Push to Hevy</button>
    <a href="/routine/daily" class="btn btn-ghost">Details</a>
  </div>
</div>`;
}

/**
 * Hero session card вҖ” the next main session from the queue.
 * Blue accent label, description preview, Push to Hevy + Details.
 */
export function heroSessionCard(routine: Routine, queueItem: QueueItemRow): string {
  const count = routine.exercises.length;
  const subtitle = routine.subtitle ?? `${count} exercises`;
  const desc = routine.description
    ? `<div class="card-desc">${escapeHtml(truncate(routine.description, 120))}</div>`
    : "";

  return `<div class="card">
  <div class="card-label" style="color: var(--blue)">Next Session</div>
  <div class="card-title">${escapeHtml(routine.title)}</div>
  <div class="card-subtitle">${escapeHtml(subtitle)}</div>
  ${desc}
  <div style="display:flex; gap:8px; margin-top:14px">
    <button class="btn btn-blue" data-on:click="@post('/api/push-hevy/${escapeAttr(queueItem.routine_id)}')">Push to Hevy</button>
    <a href="/routine/${escapeAttr(routine.id)}" class="btn btn-ghost">Details</a>
  </div>
</div>`;
}

/**
 * Completed section вҖ” items finished earlier today.
 * Shown with strikethrough text and a green checkmark.
 */
export function completedSection(items: Array<{ title: string }>): string {
  if (items.length === 0) return "";

  const rows = items
    .map(
      (item) =>
        `<div class="completed-item">
  <span class="completed-title">${escapeHtml(item.title)}</span>
  <span class="completed-check">&#10003;</span>
</div>`
    )
    .join("\n");

  return `<div class="section-header">Completed Today</div>
<div class="card">
${rows}
</div>`;
}

/**
 * Upcoming section вҖ” next sessions in queue with colored dots and spacers.
 */
export function upcomingSection(items: UpcomingItem[]): string {
  if (items.length === 0) return "";

  const rows = items
    .map((item) => {
      if (item.type === "spacer") {
        return `<div class="upcoming-item upcoming-spacer">
  <div class="upcoming-dot" style="background: var(--text-tertiary)"></div>
  <span class="upcoming-title">${escapeHtml(item.title)}</span>
</div>`;
      }

      const dotColor = item.color ?? "var(--blue)";
      const countLabel = item.exerciseCount
        ? `<span class="upcoming-count">${item.exerciseCount} exercises</span>`
        : "";

      return `<div class="upcoming-item">
  <div class="upcoming-dot" style="background: ${dotColor}"></div>
  <span class="upcoming-title">${escapeHtml(item.title)}</span>
  ${countLabel}
</div>`;
    })
    .join("\n");

  return `<div class="section-header">Coming Up</div>
<div class="card">
${rows}
</div>`;
}

