import type { QueueItemRow, WeekTemplate, Routine } from "../types";


export interface UpcomingItem {
  type: "session" | "spacer";
  routineId?: string;
  title: string;
  exerciseCount?: number;
  color?: string;
}

export function computeUpcoming(
  pendingItems: QueueItemRow[],
  template: WeekTemplate,
  routines: Routine[],
  maxSessions: number
): UpcomingItem[] {
  const routineMap = new Map(routines.map((r) => [r.id, r]));

  // Build the template rhythm: which day indices are spacers vs routines
  const templateRhythm: Array<{ type: "session" | "spacer"; routineId?: string }> = [];
  for (const day of template.days) {
    const mainIds = (day.routineIDs ?? []).filter((rid) => {
      const r = routineMap.get(rid);
      return r && !r.isDaily;
    });
    if (mainIds.length === 0 && (day.routineIDs ?? []).length > 0) {
      templateRhythm.push({ type: "spacer" });
    } else if (mainIds.length > 0) {
      for (const rid of mainIds) {
        templateRhythm.push({ type: "session", routineId: rid });
      }
    }
  }

  const result: UpcomingItem[] = [];
  let rhythmIndex = 0;
  let sessionCount = 0;

  const firstPending = pendingItems[0];
  if (firstPending) {
    for (let i = 0; i < templateRhythm.length; i++) {
      if (templateRhythm[i].routineId === firstPending.routine_id) {
        rhythmIndex = i;
        break;
      }
    }
  }

  let pendingIdx = 0;
  while (sessionCount < maxSessions && pendingIdx < pendingItems.length) {
    const rhythmSlot = templateRhythm[rhythmIndex % templateRhythm.length];

    if (rhythmSlot.type === "spacer") {
      result.push({ type: "spacer", title: "CARs only" });
    } else {
      const item = pendingItems[pendingIdx];
      const routine = routineMap.get(item.routine_id);
      result.push({
        type: "session",
        routineId: item.routine_id,
        title: routine?.title ?? item.routine_id,
        exerciseCount: routine?.exercises.length,
        color: routine?.color,
      });
      pendingIdx++;
      sessionCount++;
    }

    rhythmIndex++;
  }

  return result;
}

import { describe, it, expect } from "vitest";
import { generatePlaylist, getNextSession, getCompletedSessions } from "../../src/domain/queue";
import type { WeekTemplate, Routine, QueueItemRow } from "../../src/types";

const routines: Routine[] = [
  { id: "daily", title: "CARs", isDaily: true, exercises: [] },
  { id: "a", title: "Routine A", exercises: [] },
  { id: "b", title: "Routine B", exercises: [] },
  { id: "c", title: "Routine C", exercises: [] },
  { id: "recovery", title: "Recovery", exercises: [] },
];

const template: WeekTemplate = {
  id: "5day",
  name: "5-Day",
  days: [
    { dayOfWeek: 0, routineIDs: ["daily", "a"] },
    { dayOfWeek: 1, routineIDs: ["daily", "b"] },
    { dayOfWeek: 2, routineIDs: ["daily"] },
    { dayOfWeek: 3, routineIDs: ["daily", "c"] },
    { dayOfWeek: 4, routineIDs: ["daily", "recovery"] },
    { dayOfWeek: 5, routineIDs: [] },
    { dayOfWeek: 6, routineIDs: [] },
  ],
};

describe("generatePlaylist", () => {
  it("extracts main routines in order, skipping daily-only and rest days", () => {
    const playlist = generatePlaylist(template, routines, 1);
    const ids = playlist.map((item) => item.routine_id);
    expect(ids).toEqual(["a", "b", "c", "recovery"]);
  });

  it("repeats for multiple weeks", () => {
    const playlist = generatePlaylist(template, routines, 2);
    expect(playlist).toHaveLength(8);
    expect(playlist[4].routine_id).toBe("a");
    expect(playlist[4].position).toBe(4);
  });

  it("assigns sequential positions starting at 0", () => {
    const playlist = generatePlaylist(template, routines, 1);
    expect(playlist.map((p) => p.position)).toEqual([0, 1, 2, 3]);
  });
});

describe("getNextSession", () => {
  it("returns the first pending item", () => {
    const items: QueueItemRow[] = [
      { id: 1, user_id: "u", routine_id: "a", position: 0, status: "completed", completed_date: "2026-03-20", hevy_routine_id: null, hevy_workout_id: null },
      { id: 2, user_id: "u", routine_id: "b", position: 1, status: "pending", completed_date: null, hevy_routine_id: null, hevy_workout_id: null },
      { id: 3, user_id: "u", routine_id: "c", position: 2, status: "pending", completed_date: null, hevy_routine_id: null, hevy_workout_id: null },
    ];
    const next = getNextSession(items);
    expect(next?.routine_id).toBe("b");
  });

  it("returns null when all items are completed", () => {
    const items: QueueItemRow[] = [
      { id: 1, user_id: "u", routine_id: "a", position: 0, status: "completed", completed_date: "2026-03-20", hevy_routine_id: null, hevy_workout_id: null },
    ];
    expect(getNextSession(items)).toBeNull();
  });
});

describe("getCompletedSessions", () => {
  it("returns only sessions completed today", () => {
    const items: QueueItemRow[] = [
      { id: 1, user_id: "u", routine_id: "a", position: 0, status: "completed", completed_date: "2026-03-20", hevy_routine_id: null, hevy_workout_id: null },
      { id: 2, user_id: "u", routine_id: "b", position: 1, status: "completed", completed_date: "2026-03-21", hevy_routine_id: null, hevy_workout_id: null },
      { id: 3, user_id: "u", routine_id: "c", position: 2, status: "pending", completed_date: null, hevy_routine_id: null, hevy_workout_id: null },
    ];
    const completed = getCompletedSessions(items, "2026-03-21");
    expect(completed).toHaveLength(1);
    expect(completed[0].routine_id).toBe("b");
  });
});

