308вҶ’/** POST /api/setup вҖ” create user, generate queue, navigate to today */
309вҶ’async function handleSetup(request: Request, env: Env, userId: string, urlTemplateId?: string): Promise<Response> {
310вҶ’  let body: { apiKey?: string; startDate?: string; templateId?: string } = {};
311вҶ’  try {
312вҶ’    body = await request.json() as typeof body;
313вҶ’  } catch {
314вҶ’    // Body may be empty вҖ” that's OK, template ID comes from URL
315вҶ’  }
316вҶ’
317вҶ’  const templateId = urlTemplateId ?? body.templateId;
318вҶ’  const startDate = body.startDate || todayString();
319вҶ’  const apiKey = body.apiKey || undefined;
320вҶ’
321вҶ’  if (!templateId) {
322вҶ’    return new Response("Template ID is required", { status: 400 });
323вҶ’  }
324вҶ’
325вҶ’  const template = program.weekTemplates.find((t) => t.id === templateId);
326вҶ’  if (!template) {
327вҶ’    return new Response("Invalid template ID", { status: 400 });
328вҶ’  }
329вҶ’
330вҶ’  // Validate API key against Hevy before proceeding
331вҶ’  if (apiKey) {
332вҶ’    try {
333вҶ’      const client = new HevyClient(apiKey);
334вҶ’      await client.getExerciseTemplates(1, 1);
335вҶ’    } catch {
336вҶ’      return sseResponse(
337вҶ’        patchElements(
338вҶ’          `<div class="card"><p style="color:var(--orange)">Invalid Hevy API key. Check your key in Hevy Settings &gt; Developer and try again.</p></div>`,
339вҶ’          { selector: "#content", mode: "prepend" }
340вҶ’        )
341вҶ’      );
342вҶ’    }
343вҶ’  }
344вҶ’
345вҶ’  // Upsert user
346вҶ’  await upsertUser(env.DB, {
347вҶ’    id: userId,
348вҶ’    active_program: program.meta.title,
349вҶ’    template_id: templateId,
350вҶ’    start_date: startDate,
351вҶ’    hevy_api_key: apiKey,
352вҶ’  });
353вҶ’
354вҶ’  // Generate queue playlist
355вҶ’  const weeks = program.meta.durationWeeks || 8;
356вҶ’  const playlist = generatePlaylist(template, program.routines, weeks);
357вҶ’  if (playlist.length > 0) {
358вҶ’    await insertQueueItems(env.DB, userId, playlist);
359вҶ’  }
360вҶ’
361вҶ’  // Redirect to Today page via script injection (Datastar v1 pattern)
362вҶ’  return sseResponse(executeScript("window.location.href = '/'"));
363вҶ’}
