379вҶ’    return new Response("Routine not found", { status: 404 });
380вҶ’  }
381вҶ’
382вҶ’  const client = new HevyClient(user.hevy_api_key);
383вҶ’
384вҶ’  // Get or auto-create exercise template mappings
385вҶ’  let mappings = await getExerciseTemplateMappings(env.DB, userId);
386вҶ’  if (mappings.length === 0) {
387вҶ’    // First push: auto-match exercise templates
388вҶ’    try {
389вҶ’      const hevyTemplates = await client.getAllExerciseTemplates();
390вҶ’      const autoMatched = autoMatchExercises(program.exerciseTemplates, hevyTemplates);
391вҶ’
392вҶ’      for (const [programTemplateId, hevyTemplateId] of autoMatched) {
