401вҶ’    } catch {
402вҶ’      // If auto-match fails, continue with empty mappings
403вҶ’    }
404вҶ’  }
405вҶ’
406вҶ’  const payload = buildRoutinePayload(routine, mappings);
407вҶ’
408вҶ’  try {
409вҶ’    // Find existing queue item to update
410вҶ’    const items = await getQueueItems(env.DB, userId);
411вҶ’    const queueItem = items.find(
412вҶ’      (i) => i.routine_id === routineId && i.status === "pending"
413вҶ’    );
414вҶ’
415вҶ’    let hevyRoutineId: string;
416вҶ’    if (queueItem?.hevy_routine_id) {
417вҶ’      const updated = await client.updateRoutine(queueItem.hevy_routine_id, {
418вҶ’        title: payload.title,
419вҶ’        exercises: payload.exercises,
420вҶ’      });
421вҶ’      hevyRoutineId = updated.id;
422вҶ’    } else {
423вҶ’      const created = await client.createRoutine({
424вҶ’        title: payload.title,
425вҶ’        exercises: payload.exercises,
426вҶ’      });
427вҶ’      hevyRoutineId = created.id;
428вҶ’    }
429вҶ’
430вҶ’    if (queueItem) {
431вҶ’      await updateQueueItemHevyRoutineId(env.DB, queueItem.id, hevyRoutineId);
432вҶ’    }
433вҶ’
434вҶ’    const unmappedNote =
435вҶ’      payload.unmapped.length > 0
436вҶ’        ? `<p style="color:var(--orange);font-size:13px;margin-top:8px">${payload.unmapped.length} exercise(s) could not be mapped.</p>`
437вҶ’        : "";
438вҶ’
439вҶ’    return sseResponse(
440вҶ’      patchElements(
441вҶ’        `<div class="card"><p style="color:var(--green)">Pushed to Hevy!</p>${unmappedNote}</div>`,
442вҶ’        { selector: "#content", mode: "prepend" }
443вҶ’      )
444вҶ’    );
445вҶ’  } catch (err) {
446вҶ’    const msg = escapeHtml(err instanceof Error ? err.message : "Push failed");
447вҶ’    return sseResponse(
448вҶ’      patchElements(
449вҶ’        `<div class="card"><p style="color:var(--orange)">${msg}</p></div>`,
450вҶ’        { selector: "#content", mode: "prepend" }
451вҶ’      )
452вҶ’    );
453вҶ’  }
454вҶ’}
