 41вҶ’export class HevyClient {
 42вҶ’  private baseUrl = "https://api.hevyapp.com/v1";
 43вҶ’  private apiKey: string;
 44вҶ’  private static readonly MAX_PAGES = 50;
 45вҶ’
 46вҶ’  constructor(apiKey: string) {
 47вҶ’    this.apiKey = apiKey;
 48вҶ’  }
 49вҶ’
 50вҶ’  private async request<T>(path: string, init?: RequestInit): Promise<T> {
 51вҶ’    const url = `${this.baseUrl}${path}`;
 52вҶ’    const res = await fetch(url, {
 53вҶ’      ...init,
 54вҶ’      headers: {
 55вҶ’        "api-key": this.apiKey,
 56вҶ’        "accept": "application/json",
 57вҶ’        "content-type": "application/json",
 58вҶ’        ...(init?.headers ?? {}),
 59вҶ’      },
 60вҶ’    });
 61вҶ’
 62вҶ’    if (res.status === 429) {
 63вҶ’      throw new Error("RATE_LIMITED");
 64вҶ’    }
 65вҶ’
 66вҶ’    if (!res.ok) {
 67вҶ’      const errorBody = await res.text().catch(() => "");
 68вҶ’      console.error(`Hevy API ${res.status} ${res.statusText}: ${errorBody}`);
 69вҶ’      throw new Error(`Hevy API error: ${res.status} ${res.statusText}`);
 70вҶ’    }
 71вҶ’
 72вҶ’    return res.json() as Promise<T>;
 73вҶ’  }
