  1вҶ’import type { Routine, ExerciseTemplate, ExerciseTemplateMappingRow, QueueItemRow } from "../types";
  2вҶ’import type { HevyRoutineExercise, HevySet, HevyWorkout, HevyExerciseTemplate } from "../hevy/client";
  3вҶ’
  4вҶ’// в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
  5вҶ’// Sets string parser
  6вҶ’// в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
  7вҶ’
  8вҶ’/**
  9вҶ’ * Parse a sets string like "3Г—8", "3Г—30 sec", "2Г—45 sec", "3Г—1 min"
 10вҶ’ * into an array of HevySet objects.
 11вҶ’ *
 12вҶ’ * - Patterns containing "sec" or "min" produce duration_seconds sets.
 13вҶ’ * - All other patterns produce reps sets.
 14вҶ’ */
 15вҶ’function parseSetsString(setsStr: string): HevySet[] {
 16вҶ’  // Normalise the multiplication sign вҖ” programs may use Г— (U+00D7) or x
 17вҶ’  const normalised = setsStr.replace(/Г—/g, "x");
 18вҶ’
 19вҶ’  // Match "NxM sec", "NxM min", or "NxM"
 20вҶ’  const match = normalised.match(/^(\d+)\s*x\s*(\d+(?:\.\d+)?)\s*(sec|min)?/i);
 21вҶ’  if (!match) {
 22вҶ’    // Fallback: return a single normal set with no values
 23вҶ’    return [{ type: "normal", reps: null, repRange: { start: null, end: null } }];
 24вҶ’  }
 25вҶ’
 26вҶ’  const count = parseInt(match[1], 10);
 27вҶ’  const value = parseFloat(match[2]);
 28вҶ’  const unit = match[3]?.toLowerCase();
 29вҶ’
 30вҶ’  const isDuration = unit === "sec" || unit === "min";
 31вҶ’  const duration_seconds = isDuration
 32вҶ’    ? unit === "min"
 33вҶ’      ? Math.round(value * 60)
 34вҶ’      : Math.round(value)
 35вҶ’    : undefined;
 36вҶ’
 37вҶ’  const sets: HevySet[] = [];
 38вҶ’  for (let i = 0; i < count; i++) {
 39вҶ’    if (isDuration) {
 40вҶ’      sets.push({ type: "normal", reps: null, repRange: { start: null, end: null }, duration_seconds });
 41вҶ’    } else {
 42вҶ’      const reps = Math.round(value);
 43вҶ’      sets.push({ type: "normal", reps, repRange: { start: reps, end: reps } });
 44вҶ’    }
 45вҶ’  }
 46вҶ’  return sets;
 47вҶ’}
